/* Workplace English Data — Part 4: Chinese-Speaker Errors & Interview Skills */
(function() {
  if (typeof WORKPLACE_ENGLISH === 'undefined') return;

  // ============================================================
  // MODULE 6: CHINESE-SPEAKER ERROR PATTERNS
  // ============================================================
  WORKPLACE_ENGLISH.chineseSpeakerErrors = {
    title: "Chinese-Speaker Error Patterns",
    sections: [
      {
        id: "articles-determiners",
        title: "Articles & Determiners (a/an/the/zero)",
        theory: "Chinese has no article system. This is the #1 error pattern for Chinese speakers. English requires articles before singular countable nouns and 'the' for specific references. Rules: 'a/an' for first mention or non-specific; 'the' for specific/previously mentioned; zero article for general plurals and uncountable nouns.",
        exercises: [          {id:"ad001",type:"error",q:"She is teacher at a primary school.",a:"She is a teacher at a primary school.",exp:"Job titles with 'is' require 'a/an': 'She is a teacher.' Chinese has no equivalent — 她是老师 (tā shì lǎoshī) needs no article. This is one of the most common Chinese-speaker errors."},
          {id:"ad002",type:"fill",q:"I bought ___ new laptop yesterday. ___ laptop has a very fast processor.",a:"a ... The",exp:"First mention = 'a' (non-specific). Second mention = 'the' (now specific, we know which laptop). Chinese uses 一台 for first mention but nothing for second."},
          {id:"ad003",type:"mc",q:"Which sentence is correct?",options:["I like music.","I like the music.","I like a music.","I like musics."],a:0,exp:"'Music' is uncountable and used in the general sense here = zero article. 'The music' would mean specific music (e.g. 'the music at the party'). 'A music' and 'musics' are always wrong."},
          {id:"ad004",type:"error",q:"Can you pass me salt, please?",a:"Can you pass me the salt, please?",exp:"'The salt' — we mean the specific salt on the table. Chinese 把盐递给我 (bǎ yán dì gěi wǒ) has no article but English requires 'the' for a specific item both speakers can see."},
          {id:"ad005",type:"fill",q:"He is ___ honest person and ___ excellent colleague.",a:"an ... an",exp:"'An' before vowel sounds: 'honest' starts with a vowel sound (the 'h' is silent). 'Excellent' starts with a vowel sound. Chinese speakers often forget to switch between 'a' and 'an'."},
          {id:"ad006",type:"error",q:"I go to the school every day.",a:"I go to school every day.",exp:"'Go to school' (zero article) = attend as a student/teacher. 'Go to the school' = visit the building for another purpose. Chinese 去学校 doesn't distinguish these meanings."},
          {id:"ad007",type:"mc",q:"Choose the correct sentence about a general truth.",options:["The water boils at 100 degrees.","Water boils at 100 degrees.","A water boils at 100 degrees.","Waters boil at 100 degrees."],a:1,exp:"General truths about uncountable nouns use zero article: 'Water boils at 100 degrees.' Adding 'the' would mean specific water."},
          {id:"ad008",type:"fill",q:"She plays ___ piano beautifully. She also plays ___ tennis on weekends.",a:"the ... zero",exp:"Musical instruments take 'the': 'plays the piano.' Sports take zero article: 'plays tennis.' This is a fixed rule with no logical reason — just memorise it."},
          {id:"ad009",type:"error",q:"The life is short, so enjoy every moment.",a:"Life is short, so enjoy every moment.",exp:"Abstract/general concepts use zero article: 'Life is short.' Adding 'the' would mean a specific life. Chinese 人生很短 uses no article, but Chinese speakers sometimes overcorrect by adding 'the'."},
          {id:"ad010",type:"fill",q:"I need to go to ___ bank this afternoon. There is ___ new branch on George Street.",a:"the ... a",exp:"'The bank' = the specific bank I use. 'A new branch' = first mention, non-specific to the listener. This the/a contrast is fundamental."},          {id:"ad011",type:"error",q:"He wants to become the doctor when he grows up.",a:"He wants to become a doctor when he grows up.",exp:"Future career aspiration = 'a doctor' (one of many, non-specific). 'The doctor' would mean one particular doctor. Chinese 他想当医生 has no article."},
          {id:"ad012",type:"fill",q:"___ children learn languages faster than ___ adults.",a:"zero ... zero",exp:"General statements about groups use zero article: 'Children learn faster than adults.' Not 'The children' (that would mean specific children)."},
          {id:"ad013",type:"mc",q:"Which is correct when talking about meals in general?",options:["I had the breakfast at 7am.","I had a breakfast at 7am.","I had breakfast at 7am.","I had breakfasts at 7am."],a:2,exp:"Meals take zero article in general use: 'had breakfast', 'ate lunch', 'cooked dinner'. Exception: 'The breakfast at the hotel was excellent' (specific)."},
          {id:"ad014",type:"error",q:"She has the experience in teaching mathematics.",a:"She has experience in teaching mathematics.",exp:"'Experience' as an uncountable noun (general ability) = zero article. 'The experience' would mean a specific event. Chinese 她有教学经验 has no article — but the zero article IS correct here."},
          {id:"ad015",type:"fill",q:"We visited ___ Great Wall of China and then went to ___ restaurant nearby.",a:"the ... a",exp:"Unique landmarks always take 'the': 'the Great Wall', 'the Opera House'. First-mention restaurant = 'a restaurant'."},
          {id:"ad016",type:"error",q:"I have a good news for you.",a:"I have good news for you.",exp:"'News' is uncountable — never 'a news' or 'newses'. Chinese 一个好消息 uses the measure word 个, but English treats 'news' as uncountable. Say 'a piece of good news' if you need a countable form."},
          {id:"ad017",type:"fill",q:"She is ___ only person who can help us. She has ___ unique skill set.",a:"the ... a",exp:"'The only' — superlatives and 'only' always take 'the'. 'A unique' — 'unique' starts with a /juː/ consonant sound, so 'a' not 'an'."},
          {id:"ad018",type:"mc",q:"Select the correct use of articles with 'hospital'.",options:["He is in hospital. (He is a patient.)","He is in the hospital. (He is a patient.)","He is in a hospital. (He is a patient.)","He is at hospital working. (He is a patient.)"],a:0,exp:"British/Australian English: 'in hospital' = being treated as a patient (zero article). 'In the hospital' = inside the building (visiting, working). American English differs here."},
          {id:"ad019",type:"error",q:"The homework is very important for the students.",a:"Homework is very important for students.",exp:"General statements: 'Homework' (uncountable, general) and 'students' (general group) both take zero article. Adding 'the' makes them specific, which changes the meaning."},
          {id:"ad020",type:"fill",q:"I saw ___ interesting documentary on ___ ABC last night.",a:"an ... zero",exp:"'An interesting' — vowel sound. TV/radio stations typically take zero article: 'on ABC', 'on SBS', 'on Channel 9'. But 'on the ABC' is also acceptable in Australian English."},          {id:"ad021",type:"error",q:"Please give me information about the course.",a:"Please give me some information about the course.",exp:"'Information' is uncountable — use 'some information', not bare 'information' in requests. 'The course' is correct (specific course). Chinese 请给我信息 doesn't need 'some'."},
          {id:"ad022",type:"fill",q:"My brother is ___ engineer. He works for ___ largest construction company in Sydney.",a:"an ... the",exp:"Job title: 'an engineer' (vowel sound). Superlative: 'the largest' — superlatives always take 'the'."},
          {id:"ad023",type:"mc",q:"Which sentence correctly uses zero article?",options:["She went to the bed early.","She went to bed early.","She went to a bed early.","She went to beds early."],a:1,exp:"'Go to bed' = go to sleep (zero article, fixed expression). 'Go to the bed' = walk towards a specific bed (physical movement). Same pattern as 'go to school/work/church'."},
          {id:"ad024",type:"error",q:"The nature is beautiful in the spring.",a:"Nature is beautiful in spring.",exp:"'Nature' in the general sense = zero article. Seasons in general statements = zero article in British/Australian English. Chinese 大自然 and 春天 have no articles."},
          {id:"ad025",type:"fill",q:"There was ___ accident on ___ Pacific Highway this morning.",a:"an ... the",exp:"First mention of the event: 'an accident'. Named roads take 'the': 'the Pacific Highway', 'the Hume Highway'. But just 'George Street' (no 'the' for street names without Highway/Road)."},
          {id:"ad026",type:"error",q:"I like to read the books in my free time.",a:"I like to read books in my free time.",exp:"'Books' in general = zero article. 'The books' would mean specific books. 'In my free time' is a fixed expression. Chinese 我喜欢看书 correctly has no article — don't overcorrect."},
          {id:"ad027",type:"fill",q:"Could you open ___ window? ___ air in here is quite stuffy.",a:"a ... The",exp:"Non-specific window (any will do) = 'a window'. Specific air (in this room) = 'the air'. This a/the contrast shows the specificity distinction clearly."},
          {id:"ad028",type:"mc",q:"Which is correct for job advertisements?",options:["We are looking for teacher.","We are looking for a teacher.","We are looking for the teacher.","We are looking for teachers."],a:1,exp:"Singular job vacancy = 'a teacher'. Option 3 ('the teacher') implies a specific known person. Option 0 is missing the required article. Option 3 is correct if multiple positions are open."},
          {id:"ad029",type:"error",q:"I have the headache and need to go home.",a:"I have a headache and need to go home.",exp:"'A headache' — first mention, non-specific. Most ailments take 'a': 'a cold', 'a fever', 'a sore throat'. Exception: 'the flu'. Chinese 我头疼 uses no article at all."},
          {id:"ad030",type:"fill",q:"___ students in my class are from diverse backgrounds. ___ student from Vietnam won ___ award last week.",a:"The ... A ... an",exp:"'The students in my class' = specific group. 'A student' = one non-specific student (first mention). 'An award' = non-specific award (first mention, vowel sound)."},          {id:"ad031",type:"error",q:"Sun rises in the east and sets in the west.",a:"The sun rises in the east and sets in the west.",exp:"Unique celestial bodies take 'the': 'the sun', 'the moon', 'the earth'. Compass directions with 'in' also take 'the': 'in the east'. Chinese 太阳从东方升起 has no article."},
          {id:"ad032",type:"fill",q:"She applied for ___ position at ___ University of Melbourne.",a:"a ... the",exp:"'A position' = one of possibly many (non-specific). Universities with 'of' take 'the': 'the University of Melbourne'. But: 'Macquarie University' (no 'the' without 'of')."},
          {id:"ad033",type:"mc",q:"Which sentence about transport is correct (Australian English)?",options:["I go to work by the bus.","I go to work by bus.","I go to work by a bus.","I go to work with bus."],a:1,exp:"'By + transport' uses zero article: 'by bus', 'by train', 'by car'. Adding 'the' or 'a' is incorrect. Chinese 坐公交 also has no article, so this rule is intuitive — but many speakers overcorrect."},
          {id:"ad034",type:"error",q:"I need to buy furniture for my new apartment.",a:"I need to buy furniture for my new apartment.",exp:"This sentence is actually correct! 'Furniture' is uncountable — zero article for general uncountable nouns. No 'a' or 'the' needed. Chinese speakers sometimes add 'a' or 'some' unnecessarily."},
          {id:"ad035",type:"fill",q:"He is ___ best teacher I have ever had. He teaches ___ English at our school.",a:"the ... zero",exp:"Superlative = 'the best'. School subjects take zero article: 'teaches English', 'studies mathematics'. Not 'the English' unless you mean the English language specifically."},
          {id:"ad036",type:"error",q:"She plays a violin in the school orchestra.",a:"She plays the violin in the school orchestra.",exp:"Musical instruments take 'the': 'plays the violin', 'plays the guitar'. This is a fixed rule. 'The school orchestra' = specific orchestra at her school."},
          {id:"ad037",type:"fill",q:"I had ___ interesting conversation with ___ principal about ___ new curriculum.",a:"an ... the ... the",exp:"'An interesting' = first mention. 'The principal' = specific person (there's only one). 'The new curriculum' = specific, known to both speakers."},
          {id:"ad038",type:"mc",q:"Choose the correct article usage for places.",options:["I went to the church to pray. (I'm religious.)","I went to church to pray. (I'm religious.)","I went to a church to pray. (I'm religious.)","I went to church's to pray. (I'm religious.)"],a:1,exp:"'Go to church' (zero article) = go for the purpose of worship. 'Go to the church' = go to the building. Same pattern: 'go to prison' (as a prisoner) vs 'go to the prison' (to visit)."},
          {id:"ad039",type:"error",q:"The most of students passed the exam.",a:"Most of the students passed the exam.",exp:"'Most of the students' — 'most of' comes before 'the'. Or simply: 'Most students passed.' Never 'the most of'. Chinese 大部分学生 has a different word order."},
          {id:"ad040",type:"fill",q:"She works as ___ receptionist at ___ hotel near ___ airport.",a:"a ... a ... the",exp:"Job role: 'a receptionist'. Non-specific hotel: 'a hotel'. Specific airport (there is usually one main one): 'the airport'. Context determines specificity."},          {id:"ad041",type:"error",q:"I bought new car last weekend. Car is red.",a:"I bought a new car last weekend. The car is red.",exp:"First mention = 'a new car'. Second mention = 'the car' (now both speakers know which one). Chinese 我买了新车。车是红色的 uses no articles at all."},
          {id:"ad042",type:"fill",q:"___ poverty is a serious issue. ___ government should do more to help ___ poor.",a:"zero ... The ... the",exp:"Abstract concept in general = zero article ('Poverty'). Specific institution = 'The government'. 'The + adjective' = a group of people: 'the poor', 'the elderly', 'the unemployed'."},
          {id:"ad043",type:"mc",q:"Which sentence about nationalities is correct?",options:["The Chinese are hardworking people.","Chinese are hardworking people.","A Chinese are hardworking people.","Chinese is hardworking people."],a:0,exp:"Nationality as a group = 'The Chinese', 'The French', 'The Japanese'. This uses 'the + adjective' to represent an entire people. The verb is plural."},
          {id:"ad044",type:"error",q:"I will meet you at the corner of King Street and the George Street.",a:"I will meet you at the corner of King Street and George Street.",exp:"Street names take zero article: 'King Street', 'George Street'. But roads with 'Highway/Road/Avenue' in a descriptive sense may take 'the': 'the Pacific Highway'."},
          {id:"ad045",type:"fill",q:"There is ___ apple and ___ banana on the table. Pass me ___ apple, please.",a:"an ... a ... the",exp:"First mention: 'an apple' (vowel), 'a banana' (consonant). Second mention of apple: 'the apple' (now specific). This first/second mention rule is the core article system."},
          {id:"ad046",type:"open",q:"Correct all article errors in this paragraph: 'I am teacher. I work at school in Sydney. School is near beach. I take bus every morning. I love the teaching.'",a:"I am a teacher. I work at a school in Sydney. The school is near the beach. I take the bus every morning. I love teaching.",exp:"'A teacher' (job title). 'A school' (first mention). 'The school' (second mention). 'The beach' (specific/known). 'The bus' (the regular one). 'Teaching' (general activity, zero article)."},
          {id:"ad047",type:"error",q:"She has very good understanding of the mathematics.",a:"She has a very good understanding of mathematics.",exp:"'A good understanding' — 'understanding' here is countable (a specific type of understanding). 'Mathematics' in general = zero article. Chinese 她对数学理解很好 has no articles."},
          {id:"ad048",type:"fill",q:"I read ___ article about ___ climate change in ___ newspaper.",a:"an ... zero ... a",exp:"'An article' = non-specific article. 'Climate change' = general concept, zero article. 'A newspaper' = non-specific newspaper (or 'the newspaper' if it is your regular one)."},
          {id:"ad049",type:"mc",q:"Which sentence about 'last/next' with time is correct?",options:["I will see you the next Monday.","I will see you next Monday.","I will see you in next Monday.","I will see you at next Monday."],a:1,exp:"'Next/last + day/week/month/year' takes zero article and no preposition: 'next Monday', 'last Friday', 'next year'. Adding 'the' or 'in/at/on' is incorrect."},
          {id:"ad050",type:"error",q:"The happiness is more important than the money.",a:"Happiness is more important than money.",exp:"General abstract concepts = zero article: 'Happiness', 'Money'. Adding 'the' makes them specific. This is a philosophical statement about happiness in general. Chinese 幸福比金钱重要 needs no articles."},          {id:"ad051",type:"fill",q:"___ teacher's role is to guide ___ students, not to give them ___ answers.",a:"A ... zero ... zero",exp:"'A teacher's role' = any teacher (generic singular). 'Students' and 'answers' in general = zero article. Or 'The teacher's role' if discussing a specific concept is also acceptable."},
          {id:"ad052",type:"error",q:"I need advice about the career change.",a:"I need advice about a career change.",exp:"'Advice' is uncountable — zero article (correct here, no 'an advice'). 'A career change' = non-specific, hypothetical. 'The career change' would mean one already planned."},
          {id:"ad053",type:"fill",q:"She volunteers at ___ local hospital on ___ weekends.",a:"the ... zero",exp:"'The local hospital' = specific (the one in her area). 'On weekends' = habitual, general = zero article. Also acceptable: 'at a local hospital' if not specifying which one."},
          {id:"ad054",type:"mc",q:"Which sentence about 'home' is correct?",options:["I went to the home after work.","I went to home after work.","I went home after work.","I went to a home after work."],a:2,exp:"'Go home' — no preposition 'to' and no article. 'Home' acts as an adverb here. Chinese 我回家了 is similarly direct. But: 'I went to the nursing home' (a specific place)."},
          {id:"ad055",type:"error",q:"The English is important for the international communication.",a:"English is important for international communication.",exp:"Languages take zero article: 'English', 'Mandarin', 'French'. General concepts: 'international communication' = zero article. Chinese 英语对国际交流很重要 has no articles — and is correct to omit them here."}
        ]
      },      {
        id: "prepositions",
        title: "Prepositions (in/on/at/to/for)",
        theory: "Chinese prepositions do not map 1:1 to English. 在 (zai) covers 'in/on/at'. 到 (dao) covers 'to/arrive at'. 对 (dui) covers 'to/towards/for'. 给 (gei) covers 'to/for'. This creates systematic errors like 'arrive to school' (arrive AT), 'discuss about the topic' (discuss [no preposition]).",
        exercises: [
          {id:"pp001",type:"error",q:"I arrived to school at 8:30 this morning.",a:"I arrived at school at 8:30 this morning.",exp:"'Arrive at' a specific place (arrive at school, arrive at the airport). 'Arrive in' a city/country (arrive in Sydney). Never 'arrive to'. Chinese 到达学校 (dao da xuexiao) uses 到 which resembles 'to'."},
          {id:"pp002",type:"fill",q:"She is very good ___ mathematics but struggles ___ essay writing.",a:"at ... with",exp:"'Good at' = skilled in a subject. 'Struggle with' = have difficulty with. Chinese 擅长 (shanchang) and 困难 don't use prepositions the same way."},
          {id:"pp003",type:"mc",q:"Which sentence uses the correct preposition?",options:["I will discuss about the issue tomorrow.","I will discuss the issue tomorrow.","I will discuss on the issue tomorrow.","I will discuss for the issue tomorrow."],a:1,exp:"'Discuss' takes a direct object — NO preposition needed. 'Discuss the issue', not 'discuss about'. Chinese 讨论关于 (taolun guanyu) literally translates as 'discuss about', causing this error."},
          {id:"pp004",type:"error",q:"She explained me the process step by step.",a:"She explained the process to me step by step.",exp:"'Explain something TO someone' — 'explain' cannot take an indirect object directly. Never 'explain me'. Chinese 她给我解释 (ta gei wo jieshi) puts the person before the thing."},
          {id:"pp005",type:"fill",q:"The meeting is ___ Monday ___ 3 pm ___ the conference room.",a:"on ... at ... in",exp:"Days = 'on' (on Monday). Times = 'at' (at 3 pm). Enclosed spaces = 'in' (in the conference room). Chinese 在 (zai) covers all three — this is why preposition choice is so difficult."},
          {id:"pp006",type:"error",q:"I will wait you at the entrance.",a:"I will wait for you at the entrance.",exp:"'Wait for' someone — the preposition 'for' is required. Chinese 等你 (deng ni) needs no preposition, so speakers often drop 'for'. 'Wait' alone means to remain in place."},
          {id:"pp007",type:"fill",q:"She is interested ___ applying ___ a teaching position ___ this school.",a:"in ... for ... at",exp:"'Interested in' + gerund. 'Apply for' a job. 'At' a school/company. Three different prepositions in one sentence — each must be memorised as a collocation."},
          {id:"pp008",type:"mc",q:"Choose the correct preposition: 'I depend ___ my colleagues for support.'",options:["in","on","at","to"],a:1,exp:"'Depend on' = rely on. Chinese 依赖 (yilai) doesn't always signal which preposition to use. Also: 'rely on', 'count on', 'insist on'."},
          {id:"pp009",type:"error",q:"She married with a teacher from Brisbane.",a:"She married a teacher from Brisbane.",exp:"'Marry someone' — NO preposition. Never 'married with'. Chinese 和...结婚 (he...jiehun) literally means 'with...marry', causing this systematic error. Also correct: 'got married to'."},
          {id:"pp010",type:"fill",q:"I apologised ___ the mistake and asked ___ another chance.",a:"for ... for",exp:"'Apologise for' something. 'Ask for' something. Both use 'for' but for different reasons — 'for' can indicate cause (apologise for) or desire (ask for)."},
          {id:"pp011",type:"error",q:"Please reply me as soon as possible.",a:"Please reply to me as soon as possible.",exp:"'Reply to' someone. Chinese 回复我 (huifu wo) needs no preposition. Similarly: 'respond to', 'listen to', 'speak to'. These are verbs that require 'to' before the person."},
          {id:"pp012",type:"fill",q:"The report consists ___ three sections and focuses ___ student outcomes.",a:"of ... on",exp:"'Consist of' = be made up of. 'Focus on' = concentrate on. These are fixed verb-preposition combinations that must be memorised."},
          {id:"pp013",type:"mc",q:"Choose the correct preposition: 'She is responsible ___ the Year 7 programme.'",options:["of","about","for","with"],a:2,exp:"'Responsible for' = in charge of. Chinese 负责 (fuze) is followed directly by the object, no preposition needed in Chinese. Also: 'accountable for', 'in charge of'."},
          {id:"pp014",type:"error",q:"I entered into the classroom and sat on my seat.",a:"I entered the classroom and sat in my seat.",exp:"'Enter' takes a direct object — no 'into'. 'Sit in' a seat/chair (you are enclosed by it). Chinese 进入 (jinru) literally contains 'into' (进=enter, 入=into), causing 'entered into'."},
          {id:"pp015",type:"fill",q:"He was absent ___ school ___ Monday because he was sick ___ the flu.",a:"from ... on ... with",exp:"'Absent from' a place. 'On' a specific day. 'Sick with' an illness. Each preposition has a specific role that differs from Chinese patterns."},          {id:"pp016",type:"error",q:"I participated the workshop last Friday.",a:"I participated in the workshop last Friday.",exp:"'Participate in' an event. Chinese 参加 (canjia) takes a direct object without a preposition. Similarly: 'take part in', 'engage in', 'be involved in'."},
          {id:"pp017",type:"fill",q:"The students complained ___ the homework load and asked ___ more time.",a:"about ... for",exp:"'Complain about' a problem. 'Ask for' something desired. Chinese 抱怨 (baoyuan) and 要求 (yaoqiu) use different preposition patterns than English."},
          {id:"pp018",type:"mc",q:"Which is correct: 'I am ___ home right now'?",options:["in","on","at","to"],a:2,exp:"'At home' — fixed expression. Not 'in home' or 'on home'. But: 'in my house' (inside the building). Chinese 在家 (zai jia) uses 在 which could map to any preposition."},
          {id:"pp019",type:"error",q:"She insisted to finish the project by herself.",a:"She insisted on finishing the project by herself.",exp:"'Insist on' + gerund. Not 'insist to'. Chinese 坚持 (jianchi) + verb doesn't require a preposition, so speakers often use 'to' by analogy. Also: 'persist in', 'succeed in'."},
          {id:"pp020",type:"fill",q:"I congratulated her ___ her promotion and wished her success ___ her new role.",a:"on ... in",exp:"'Congratulate someone on' an achievement. 'Success in' a field/role. Chinese 祝贺 (zhuhe) and 成功 (chenggong) use different constructions."},
          {id:"pp021",type:"error",q:"He is afraid about making mistakes in front of the class.",a:"He is afraid of making mistakes in front of the class.",exp:"'Afraid of' — not 'afraid about'. Chinese 害怕 (haipa) doesn't distinguish. Similarly: 'scared of', 'terrified of', 'frightened of'. 'Worried about' is different — 'about' is correct there."},
          {id:"pp022",type:"fill",q:"The difference ___ British and Australian English is small, but it depends ___ the context.",a:"between ... on",exp:"'Difference between' two things. 'Depend on' = be determined by. 'Between' is used for two items; 'among' for three or more."},
          {id:"pp023",type:"mc",q:"Which preposition completes: 'She is accustomed ___ the Australian way of life'?",options:["with","in","for","to"],a:3,exp:"'Accustomed to' = used to. Chinese 习惯 (xiguan) takes a direct object. Similarly: 'used to', 'adapted to', 'adjusted to' all take 'to'."},
          {id:"pp024",type:"error",q:"He prevented me to leave the meeting early.",a:"He prevented me from leaving the meeting early.",exp:"'Prevent someone from doing something'. Chinese 阻止我离开 (zuzhi wo likai) uses no preposition. Similarly: 'stop someone from', 'prohibit someone from'."},
          {id:"pp025",type:"fill",q:"I am looking ___ a new apartment ___ the city. I prefer living ___ the top floor.",a:"for ... in ... on",exp:"'Look for' = search for. 'In the city' = within the city area. 'On the top floor' = floors use 'on'. Chinese 在 covers all three spatial meanings."},          {id:"pp026",type:"error",q:"I contacted with the parents about their child's progress.",a:"I contacted the parents about their child's progress.",exp:"'Contact' takes a direct object — no 'with'. Chinese 联系 (lianxi) can be followed by 与 (yu, 'with'), causing this transfer error. Simply: 'contact someone'."},
          {id:"pp027",type:"fill",q:"She specialises ___ teaching English ___ second language learners.",a:"in ... to",exp:"'Specialise in' a field. 'English to second language learners' — 'to' means directed towards. Chinese 专门 (zhuanmen) doesn't require a preposition."},
          {id:"pp028",type:"mc",q:"Choose the correct sentence about 'agree'.",options:["I agree with your suggestion.","I agree your suggestion.","I agree to your suggestion. (meaning: I share your view)","I agree about your suggestion. (meaning: I share your view)"],a:0,exp:"'Agree with' a person or opinion (share the view). 'Agree to' a plan (accept/consent). 'Agree on' a topic (reach consensus). Each preposition changes the meaning."},
          {id:"pp029",type:"error",q:"She suffers from headaches and is allergic with pollen.",a:"She suffers from headaches and is allergic to pollen.",exp:"'Suffer from' an illness. 'Allergic to' something. Not 'allergic with'. Chinese 对...过敏 (dui...guomin) uses 对 which often maps to 'to' but not always predictably."},
          {id:"pp030",type:"fill",q:"The teacher provided the students ___ all the resources they needed ___ the project.",a:"with ... for",exp:"'Provide someone with something' or 'provide something for someone'. Both patterns are correct. Chinese 提供 (tigong) uses different structures."},
          {id:"pp031",type:"error",q:"She graduated the university in 2019.",a:"She graduated from the university in 2019.",exp:"'Graduate from' an institution. Chinese 毕业于 (biye yu) uses 于 which doesn't directly map to 'from'. American English sometimes allows 'graduated university' informally, but Australian English prefers 'from'."},
          {id:"pp032",type:"fill",q:"I was disappointed ___ the results but hopeful ___ improvement next term.",a:"with ... for",exp:"'Disappointed with/in' results. 'Hopeful for' future outcomes. Adjective + preposition combinations must be learned individually."},
          {id:"pp033",type:"mc",q:"Which preposition follows 'different'?",options:["Different with","Different than","Different from","Different of"],a:2,exp:"'Different from' is correct in British/Australian English. 'Different than' is American English. Never 'different with' or 'different of'. Chinese 不同于 (butong yu) doesn't help predict the English preposition."},
          {id:"pp034",type:"error",q:"I emphasised on the importance of punctuality.",a:"I emphasised the importance of punctuality.",exp:"'Emphasise' takes a direct object — no 'on'. Chinese 强调 (qiangdiao) is similar (no preposition), but speakers sometimes add 'on' by analogy with 'focus on'. However, 'place emphasis on' does use 'on'."},
          {id:"pp035",type:"fill",q:"He complained ___ the principal ___ the unfair treatment ___ the staff meeting.",a:"to ... about ... at",exp:"'Complain to' a person (recipient). 'Complain about' an issue (topic). 'At the meeting' (location/event). Three prepositions, three distinct roles."},          {id:"pp036",type:"error",q:"We need to cope up with the increasing workload.",a:"We need to cope with the increasing workload.",exp:"'Cope with' — no 'up'. Chinese speakers sometimes add 'up' by analogy with 'keep up with'. 'Cope with' = manage/handle a difficulty."},
          {id:"pp037",type:"fill",q:"The school invested ___ new technology and spent a lot ___ staff training.",a:"in ... on",exp:"'Invest in' = put money/resources into. 'Spend money on' something. Chinese 投资 (touzi) and 花费 (huafei) use different constructions."},
          {id:"pp038",type:"mc",q:"Complete: 'She reminded me ___ the deadline.'",options:["for","about","on","to"],a:1,exp:"'Remind someone about/of' something. Both 'about' and 'of' are correct. Not 'remind for' or 'remind on'. Chinese 提醒 (tixing) takes a direct structure."},
          {id:"pp039",type:"error",q:"I don't believe to ghosts, but I believe on science.",a:"I don't believe in ghosts, but I believe in science.",exp:"'Believe in' = accept the existence or truth of something. Not 'believe to' or 'believe on'. Chinese 相信 (xiangxin) takes a direct object without a preposition."},
          {id:"pp040",type:"fill",q:"He borrowed a book ___ the library and returned it ___ time.",a:"from ... on",exp:"'Borrow from' a source. 'On time' = punctually (fixed expression). Also: 'in time' = before the deadline (different meaning). Chinese 从...借 (cong...jie) uses 从 which maps to 'from' here."},
          {id:"pp041",type:"error",q:"She is capable to handle the situation independently.",a:"She is capable of handling the situation independently.",exp:"'Capable of' + gerund. Not 'capable to'. Chinese 能够 (nenggou) is followed by a verb directly. Similarly: 'incapable of', 'fond of', 'tired of'."},
          {id:"pp042",type:"fill",q:"We have been living ___ Australia ___ 2018. We moved here ___ July.",a:"in ... since ... in",exp:"'In' a country. 'Since' a specific point in time (2018). 'In' a month. Chinese 自从 (zicong) maps to 'since', but 在 (zai) is used for both 'in Australia' and 'in July'."},
          {id:"pp043",type:"mc",q:"Choose the correct sentence about 'inform'.",options:["Please inform about me the changes.","Please inform me about the changes.","Please inform me for the changes.","Please inform to me the changes."],a:1,exp:"'Inform someone about/of something'. The person comes directly after 'inform', then 'about' or 'of' introduces the topic. Chinese 通知我关于 (tongzhi wo guanyu) follows a similar order."},
          {id:"pp044",type:"error",q:"I am looking forward to meet you at the conference.",a:"I am looking forward to meeting you at the conference.",exp:"'Look forward to' + gerund (-ing). Here 'to' is a preposition, not part of an infinitive. This tricks many learners. Chinese 期待见到你 uses a verb, not a gerund."},
          {id:"pp045",type:"fill",q:"The exam consists ___ two parts: a written section and ___ oral presentation.",a:"of ... an",exp:"'Consist of' = be composed of. 'An oral' — 'oral' starts with a vowel sound, so 'an'. Note: 'consist of' is never passive — never say 'is consisted of'."},
          {id:"pp046",type:"error",q:"He regards himself like an expert in the field.",a:"He regards himself as an expert in the field.",exp:"'Regard as' = consider to be. Not 'regard like'. Chinese 把自己当作 (ba ziji dangzuo) doesn't map to 'like'. Similarly: 'view as', 'see as', 'describe as'."},
          {id:"pp047",type:"fill",q:"She takes pride ___ her work and pays attention ___ every detail.",a:"in ... to",exp:"'Take pride in' = be proud of. 'Pay attention to' = focus on. These are fixed phrases that must be memorised as units."},
          {id:"pp048",type:"mc",q:"Complete: 'The decision resulted ___ a major improvement in student outcomes.'",options:["with","to","in","for"],a:2,exp:"'Result in' = lead to/cause. 'Result from' = be caused by. The direction matters: the cause results in the effect; the effect results from the cause."},
          {id:"pp049",type:"error",q:"She is very familiar about Australian curriculum standards.",a:"She is very familiar with Australian curriculum standards.",exp:"'Familiar with' = having knowledge of. Not 'familiar about'. Chinese 熟悉 (shuxi) takes a direct object. Similarly: 'acquainted with', 'comfortable with'."},
          {id:"pp050",type:"open",q:"Correct all preposition errors: 'I arrived to the school at 8am, entered into my classroom, and began to prepare to the lesson. I am responsible about Year 8 English.'",a:"I arrived at the school at 8am, entered my classroom, and began to prepare for the lesson. I am responsible for Year 8 English.",exp:"Arrive AT (not to). Enter + direct object (no into). Prepare FOR (not to). Responsible FOR (not about). These are four of the most common Chinese-speaker preposition errors."},
          {id:"pp051",type:"fill",q:"I objected ___ the proposal because it was unfair ___ the junior staff.",a:"to ... to",exp:"'Object to' = oppose. 'Unfair to' people affected. Both use 'to' but for different reasons — direction of opposition vs. direction of unfairness."},
          {id:"pp052",type:"error",q:"She insisted me to attend the meeting.",a:"She insisted that I attend the meeting.",exp:"'Insist that someone do something' (subjunctive) or 'insist on someone doing something'. Never 'insist someone to do'. Chinese 坚持要我 (jianchi yao wo) creates this transfer pattern."}
        ]
      },      {
        id: "tense-consistency",
        title: "Tense Consistency & Time Markers",
        theory: "Chinese does not conjugate verbs for tense — tense is indicated by context words (了 le, 过 guo, 会 hui, 正在 zhengzai). English requires consistent verb forms throughout. Common errors: mixing past/present in narratives, forgetting '-ed' endings, using 'will' instead of 'would' in reported speech.",
        exercises: [
          {id:"tc001",type:"error",q:"Yesterday I go to the staff meeting and discuss the new policy.",a:"Yesterday I went to the staff meeting and discussed the new policy.",exp:"'Yesterday' signals past tense — ALL verbs must be past: 'went', 'discussed'. Chinese uses 了 (le) for completion but never changes the verb form. This is perhaps the most frequent Chinese-speaker tense error."},
          {id:"tc002",type:"fill",q:"She ___ (teach) at this school since 2019 and ___ (enjoy) every year so far.",a:"has taught ... has enjoyed",exp:"'Since 2019' = present perfect required. The action started in the past and continues to now. Chinese 自从2019年她在这所学校教书 uses no tense change."},
          {id:"tc003",type:"mc",q:"Which sentence has consistent tense?",options:["I walked into the room and see a strange object on the desk.","I walked into the room and saw a strange object on the desk.","I walk into the room and saw a strange object on the desk.","I walking into the room and seeing a strange object."],a:1,exp:"Past narrative = all verbs in past: 'walked...saw'. Mixing 'walked...see' or 'walk...saw' is inconsistent. Chinese verbs never change form, so tense mixing is extremely common."},
          {id:"tc004",type:"error",q:"She said she will come to the meeting tomorrow.",a:"She said she would come to the meeting tomorrow.",exp:"Reported speech: 'said' (past) shifts 'will' to 'would'. This is called backshift. Chinese 她说她会来 doesn't change 会 (hui) regardless of reporting time."},
          {id:"tc005",type:"fill",q:"By the time I ___ (arrive) at school, the assembly ___ already ___ (start).",a:"arrived ... had ... started",exp:"Past perfect ('had started') for the earlier action; simple past ('arrived') for the later one. Chinese uses 已经 (yijing, 'already') instead of changing verb forms."},
          {id:"tc006",type:"error",q:"When I was young, I always play outside after school.",a:"When I was young, I always played outside after school.",exp:"'When I was young' = past time frame. 'Always played' must be past tense. Chinese 小时候我总是在外面玩 doesn't conjugate 玩 (wan, 'play')."},
          {id:"tc007",type:"fill",q:"She ___ (work) on the report all morning and finally ___ (submit) it at noon.",a:"worked ... submitted",exp:"Narrative past: two completed sequential actions. Both verbs take simple past. Chinese might use 了 for the second verb only, but English requires past tense for both."},
          {id:"tc008",type:"mc",q:"Choose the correct reported speech.",options:["He told me he is feeling sick.","He told me he was feeling sick.","He told me he has been feeling sick.","He told me he will feel sick."],a:1,exp:"'Told' (past) triggers backshift: 'is feeling' becomes 'was feeling'. If we want to show the illness is ongoing, 'had been feeling' is also acceptable."},
          {id:"tc009",type:"error",q:"I have been to Sydney last year and visit the Opera House.",a:"I went to Sydney last year and visited the Opera House.",exp:"'Last year' = specific past time = simple past, not present perfect. 'Have been' cannot be used with finished time markers. Chinese 去年我去了悉尼 uses 了 but doesn't change verb forms."},
          {id:"tc010",type:"fill",q:"If she ___ (study) harder, she ___ (pass) the exam. But she didn't, so she failed.",a:"had studied ... would have passed",exp:"Third conditional (unreal past): 'If + past perfect, would have + past participle'. This expresses regret about something that didn't happen. Chinese 如果她更努力学习就会通过 uses no special verb forms."},          {id:"tc011",type:"error",q:"She work here for five years now.",a:"She has worked here for five years now.",exp:"'For five years now' = started in the past and continues = present perfect. Not simple present. Chinese 她在这里工作五年了 uses 了 but no verb form change."},
          {id:"tc012",type:"fill",q:"While I ___ (mark) essays last night, my phone ___ (ring) three times.",a:"was marking ... rang",exp:"Past continuous ('was marking') for the ongoing background action. Simple past ('rang') for the interrupting events. Chinese doesn't distinguish these."},
          {id:"tc013",type:"mc",q:"Which is correct for a recently completed action with present relevance?",options:["I just finish the report.","I just finished the report.","I have just finished the report.","I am just finishing the report."],a:2,exp:"'Have just finished' = present perfect with 'just' for very recent completion with present relevance. Australian/British English prefers present perfect here. American English accepts simple past."},
          {id:"tc014",type:"error",q:"The students study very hard last term and improve their grades.",a:"The students studied very hard last term and improved their grades.",exp:"'Last term' = past time marker. All verbs must be past: 'studied', 'improved'. Adding '-ed' to regular verbs is essential — Chinese speakers often produce the base form instead."},
          {id:"tc015",type:"fill",q:"By next Friday, we ___ (complete) all the assessments and ___ (submit) the marks.",a:"will have completed ... will have submitted",exp:"Future perfect: 'By + future time' = 'will have + past participle'. Both actions will be done before Friday. Chinese 到下周五我们会完成 uses 会 (hui) but no special completion form."},
          {id:"tc016",type:"error",q:"I am knowing the answer. Let me tell you.",a:"I know the answer. Let me tell you.",exp:"'Know' is a stative verb — it cannot be used in continuous form. Never 'I am knowing' or 'I am understanding'. Chinese 我知道 is always simple, but speakers sometimes overcorrect into continuous."},
          {id:"tc017",type:"fill",q:"She ___ (not attend) the meeting because she ___ (already leave) for the day.",a:"did not attend ... had already left",exp:"Simple past for the main event ('did not attend'). Past perfect for the earlier action ('had already left'). The past perfect shows which happened first."},
          {id:"tc018",type:"mc",q:"Choose the correct tense for habitual past actions.",options:["When I was a child, I am playing in the park every day.","When I was a child, I used to play in the park every day.","When I was a child, I have played in the park every day.","When I was a child, I was playing in the park every day."],a:1,exp:"'Used to + verb' for habitual past actions no longer happening. 'Would play' is also acceptable for repeated past actions. Chinese 小时候我经常 doesn't change verb forms."},
          {id:"tc019",type:"error",q:"She tell me that she finish the report already.",a:"She told me that she had already finished the report.",exp:"Three tense errors: 'tell' should be 'told' (past). 'Finish' should be 'had finished' (past perfect for earlier event). 'Already' goes before the main verb. Chinese tense is entirely context-based."},
          {id:"tc020",type:"fill",q:"I ___ (live) in China before I ___ (move) to Australia in 2015.",a:"had lived ... moved",exp:"Past perfect ('had lived') for the earlier period. Simple past ('moved') for the specific event. 'Before' helps signal the sequence, but English still requires correct tense forms."},          {id:"tc021",type:"error",q:"After the bell ring, the students leave the classroom quickly.",a:"After the bell rang, the students left the classroom quickly.",exp:"Past narrative: 'rang' and 'left'. Irregular verbs (ring-rang-rung, leave-left-left) are especially difficult because Chinese speakers must memorise each form individually."},
          {id:"tc022",type:"fill",q:"Right now, the students ___ (complete) their assessments while I ___ (monitor) the room.",a:"are completing ... am monitoring",exp:"Present continuous for actions happening right now. Both 'are completing' and 'am monitoring' are ongoing at this moment. Chinese 正在 (zhengzai) signals this but doesn't change verb form."},
          {id:"tc023",type:"mc",q:"Choose the correct conditional.",options:["If I have more time, I will prepare better lessons.","If I have more time, I would prepare better lessons.","If I had more time, I will prepare better lessons.","If I have more time, I prepared better lessons."],a:0,exp:"First conditional (real possibility): 'If + present simple, will + base verb'. Second conditional would be: 'If I had more time, I would prepare...' (hypothetical). Don't mix them."},
          {id:"tc024",type:"error",q:"The meeting was cancel because the principal is sick.",a:"The meeting was cancelled because the principal was sick.",exp:"'Was cancelled' = passive past. 'Was sick' = past tense (the reason existed at that past time). Mixing past and present tense in one clause about the same time is inconsistent."},
          {id:"tc025",type:"fill",q:"She ___ (never travel) overseas before she ___ (get) this teaching exchange opportunity.",a:"had never travelled ... got",exp:"Past perfect for the earlier situation ('had never travelled'). Simple past for the event that changed things ('got'). Note Australian spelling: 'travelled' with double 'l'."},
          {id:"tc026",type:"error",q:"I have met her yesterday at the conference.",a:"I met her yesterday at the conference.",exp:"'Yesterday' = specific finished time = simple past only. Present perfect ('have met') cannot be used with specific past time markers. Chinese 我昨天在会议上见到了她 uses 了 but this doesn't map to present perfect."},
          {id:"tc027",type:"fill",q:"By the time the students ___ (graduate), they ___ (study) English for at least 12 years.",a:"graduate ... will have studied",exp:"Future perfect: 'By the time + present simple, will have + past participle'. The present simple in the time clause is correct — English uses present for future in time clauses."},
          {id:"tc028",type:"mc",q:"Which sentence correctly uses the present perfect?",options:["I have gone to Japan three times.","I have been to Japan three times.","I have went to Japan three times.","I have go to Japan three times."],a:1,exp:"'Have been to' = visited and returned. 'Have gone to' = currently there. 'Went' and 'go' are wrong forms after 'have'. Chinese 我去过日本三次 uses 过 (guo) for experience."},
          {id:"tc029",type:"error",q:"The school build a new library last year. It is very modern.",a:"The school built a new library last year. It is very modern.",exp:"'Built' is the past tense of 'build' (build-built-built). 'Is' is correct for the second sentence because the library still IS modern now. Tense can change between sentences if the time reference changes."},
          {id:"tc030",type:"fill",q:"I ___ (teach) for ten years now. Before that, I ___ (work) as a translator.",a:"have been teaching ... worked",exp:"Present perfect continuous ('have been teaching') for an action ongoing for a duration up to now. Simple past ('worked') for a completed previous career."},
          {id:"tc031",type:"error",q:"She said that the earth is flat.",a:"She said that the earth is round.",exp:"Actually, the grammar IS correct here — general truths keep present tense even in reported speech: 'She said the earth IS round.' The error is factual, not grammatical. But note: permanent truths don't backshift."},
          {id:"tc032",type:"fill",q:"When I ___ (walk) into the staffroom, everyone ___ (already finish) their morning tea.",a:"walked ... had already finished",exp:"Simple past for the arriving action. Past perfect for the earlier completed action. This sequence (past + past perfect) shows clear timeline ordering."},
          {id:"tc033",type:"mc",q:"Which tense is correct for a school newsletter reporting recent events?",options:["Last week, Year 10 students compete in the athletics carnival.","Last week, Year 10 students competed in the athletics carnival.","Last week, Year 10 students have competed in the athletics carnival.","Last week, Year 10 students are competing in the athletics carnival."],a:1,exp:"'Last week' = past time = simple past. School newsletters and reports use simple past for completed events. Present perfect would only work without 'last week'."},
          {id:"tc034",type:"error",q:"I didn't saw him at the meeting yesterday.",a:"I didn't see him at the meeting yesterday.",exp:"After 'did/didn't', use the BASE form: 'didn't see', not 'didn't saw'. The auxiliary 'did' already carries the past tense. Chinese speakers sometimes double-mark the past."},
          {id:"tc035",type:"fill",q:"The students ___ (present) their projects next Tuesday. They ___ (prepare) for weeks.",a:"will present ... have been preparing",exp:"Future event: 'will present' or 'are presenting'. Current preparation: 'have been preparing' (present perfect continuous for action leading up to the future event)."},
          {id:"tc036",type:"error",q:"Every day she wake up at 6am, eat breakfast, and drive to school.",a:"Every day she wakes up at 6am, eats breakfast, and drives to school.",exp:"'Every day' = habitual present = third person singular 's': 'wakes', 'eats', 'drives'. Forgetting the third-person -s is extremely common for Chinese speakers because Chinese verbs never conjugate."},
          {id:"tc037",type:"open",q:"Rewrite this paragraph with consistent past tense: 'Last Monday I arrive at school early. I am preparing my lessons when the fire alarm goes off. All students leave the building. The drill lasts 20 minutes.'",a:"Last Monday I arrived at school early. I was preparing my lessons when the fire alarm went off. All students left the building. The drill lasted 20 minutes.",exp:"All verbs must be past: arrived, was preparing (past continuous for background action), went off, left, lasted. 'When' signals the interruption pattern: past continuous + simple past."},
          {id:"tc038",type:"fill",q:"She ___ (not finish) the marking yet, but she ___ (plan) to complete it tonight.",a:"has not finished ... plans",exp:"Present perfect ('has not finished') for an action not yet completed. Simple present ('plans') for a current intention. 'Yet' is a key signal for present perfect."},
          {id:"tc039",type:"error",q:"He has been working here since three years.",a:"He has been working here for three years.",exp:"'Since' = a specific point in time (since 2020, since Monday). 'For' = a duration of time (for three years, for two weeks). Chinese 三年了 doesn't distinguish between the two."},
          {id:"tc040",type:"fill",q:"If I ___ (know) about the meeting, I ___ (attend) it. But nobody told me.",a:"had known ... would have attended",exp:"Third conditional (past unreal): 'If + past perfect, would have + past participle'. This expresses regret. Chinese 如果我知道我就会参加 uses no special tense forms."},
          {id:"tc041",type:"error",q:"The students was talking when the teacher come in.",a:"The students were talking when the teacher came in.",exp:"'Students' = plural = 'were' (not 'was'). 'Came in' = simple past. Subject-verb agreement ('was/were') combined with tense errors is a double challenge for Chinese speakers."},
          {id:"tc042",type:"mc",q:"Choose the correct future form for a scheduled event.",options:["The exam will be next Thursday.","The exam is next Thursday.","The exam was next Thursday.","The exam has been next Thursday."],a:1,exp:"Scheduled/timetabled future events use present simple: 'The exam is next Thursday.' 'The train leaves at 9am.' This is counter-intuitive — present tense for future meaning."}
        ]
      },      {
        id: "word-order-chinglish",
        title: "Word Order & Chinglish Patterns",
        theory: "Chinese word order differs from English in systematic ways. Common Chinglish patterns: topic-comment structure ('This book I already read'), double subjects ('My friend he is a teacher'), time before place ('I yesterday at school studied'), negative before modal ('I not can go').",
        exercises: [
          {id:"wo001",type:"error",q:"My friend he is a teacher in Melbourne.",a:"My friend is a teacher in Melbourne.",exp:"Double subject: Chinese topic-comment structure 我朋友他是老师 (wo pengyou ta shi laoshi) uses both 'my friend' and 'he'. English only needs one subject."},
          {id:"wo002",type:"error",q:"This book I already read it last week.",a:"I already read this book last week.",exp:"Chinese topic-comment: 这本书我已经看了 puts the topic ('this book') first. English uses Subject-Verb-Object: 'I read this book.' Also, no repeated pronoun 'it'."},
          {id:"wo003",type:"fill",q:"I go to the gym ___ ___ ___ (three times a week).",a:"three times a week",exp:"Frequency expressions go at the END of the sentence in English. Chinese 我一周三次去健身房 puts frequency BEFORE the verb. English: 'I go to the gym three times a week.'"},
          {id:"wo004",type:"error",q:"I yesterday at school had a meeting.",a:"I had a meeting at school yesterday.",exp:"Chinese time-place order: 我昨天在学校开了个会 = time before place. English: Subject + Verb + Object + Place + Time. Time and place go AFTER the verb in English."},
          {id:"wo005",type:"mc",q:"Which sentence has correct English word order?",options:["I very much like this school.","I like this school very much.","Very much I like this school.","I like very much this school."],a:1,exp:"Adverbs of degree ('very much') go AFTER the object: 'I like this school very much.' Chinese 我非常喜欢 puts the adverb BEFORE the verb, creating 'I very much like'."},
          {id:"wo006",type:"error",q:"She not can come to the meeting today.",a:"She cannot come to the meeting today.",exp:"Chinese negation: 她不能来 puts negative 不 (bu) before the modal 能 (neng). English: the negative merges with the modal: 'cannot/can't'. Never 'not can'."},
          {id:"wo007",type:"fill",q:"Although ___ was raining, ___ still went for a walk.",a:"it ... she",exp:"Chinese often omits the subject: 虽然下雨,还是去散步了. English REQUIRES a subject in every clause: 'Although it was raining, she still went.' No subjectless clauses in English."},
          {id:"wo008",type:"error",q:"Because I was tired, so I went home early.",a:"Because I was tired, I went home early.",exp:"Chinese uses 因为...所以... (yinwei...suoyi...) with BOTH connectors. English uses EITHER 'because' OR 'so', never both together. This is one of the most recognisable Chinglish patterns."},
          {id:"wo009",type:"mc",q:"Which sentence has correct adverb placement?",options:["He always is late to class.","He is always late to class.","Always he is late to class.","He is late always to class."],a:1,exp:"Frequency adverbs (always, often, never) go AFTER 'be' but BEFORE other verbs: 'He is always late' but 'He always arrives late.' Chinese 他总是迟到 puts the adverb before the verb."},
          {id:"wo010",type:"error",q:"The weather today is very good. We should go outside enjoy the sunshine.",a:"The weather today is very good. We should go outside and enjoy the sunshine.",exp:"Chinese serial verb constructions: 出去享受阳光 chains verbs without connectors. English requires 'and' between two main verbs: 'go outside AND enjoy'. Or: 'go outside TO enjoy' (purpose)."},          {id:"wo011",type:"error",q:"Although she is young, but she is very experienced.",a:"Although she is young, she is very experienced.",exp:"Same pattern as wo008: Chinese 虽然...但是... uses both. English: 'Although...,' (no 'but') OR no 'Although' + 'but she is...'. Choose one connector, not both."},
          {id:"wo012",type:"fill",q:"I have ___ been to Japan. I would love to visit ___.",a:"never ... someday",exp:"'Never' goes BEFORE the past participle: 'have never been'. Chinese 我从来没去过日本 puts 从来没 before the verb too, which happens to match here."},
          {id:"wo013",type:"error",q:"She gave to me a very useful suggestion.",a:"She gave me a very useful suggestion.",exp:"'Give someone something' — no 'to' with the double-object pattern. Chinese 她给了我一个建议 uses 给 (gei, 'to/for') explicitly. Alternatively: 'She gave a suggestion to me.'"},
          {id:"wo014",type:"mc",q:"Which question is grammatically correct?",options:["You can help me?","Can you help me?","Help me you can?","You help me can?"],a:1,exp:"English questions invert the subject and auxiliary: 'Can you...?' Chinese questions keep normal word order and add 吗 (ma): 你能帮我吗? This causes Chinese speakers to produce statements with question intonation."},
          {id:"wo015",type:"error",q:"I want to know what is his phone number.",a:"I want to know what his phone number is.",exp:"Indirect questions use STATEMENT word order: 'what his number is' (not 'what is his number'). Chinese 我想知道他的电话号码是什么 puts the question word at the end."},
          {id:"wo016",type:"fill",q:"Not only ___ she an excellent teacher, but she ___ also a caring mentor.",a:"is ... is",exp:"'Not only...but also' with inversion: 'Not only IS she..., but she IS also...'. When 'not only' starts a clause, the subject and verb invert. This is a formal pattern."},
          {id:"wo017",type:"error",q:"I don't know where is the library.",a:"I don't know where the library is.",exp:"Embedded questions: 'where the library IS' (statement order). Direct question: 'Where IS the library?' (inverted). Chinese word order is the same for both, causing this common error."},
          {id:"wo018",type:"mc",q:"Which sentence correctly places the adjective?",options:["She bought a red beautiful big car.","She bought a beautiful big red car.","She bought a big red beautiful car.","She bought a car beautiful big red."],a:1,exp:"English adjective order: Opinion-Size-Colour: 'beautiful big red car'. Chinese adjective order differs. Also: adjectives go BEFORE the noun in English (not after, as in some languages)."},
          {id:"wo019",type:"error",q:"I very like Australian food.",a:"I really like Australian food.",exp:"'Very' cannot modify verbs in English. Use 'really' or 'very much': 'I really like' or 'I like it very much.' Chinese 我很喜欢 uses 很 (hen, 'very') before verbs, causing 'I very like'."},
          {id:"wo020",type:"fill",q:"Could you tell me ___ the meeting ___ at?",a:"what time ... starts",exp:"Indirect question: 'what time the meeting starts' (statement order). Not 'what time does the meeting start' when embedded. The main clause already shows it is a question."},          {id:"wo021",type:"error",q:"Even though the exam was hard, but most students passed.",a:"Even though the exam was hard, most students passed.",exp:"'Even though...but' = double connector (same as although...but). Chinese 即使...但是... uses both. English only needs one: 'Even though' already implies the contrast."},
          {id:"wo022",type:"fill",q:"She is ___ a hard-working teacher ___ all her colleagues respect her.",a:"such ... that",exp:"'Such a + noun + that' for emphasis. Chinese 她是如此努力以至于 follows a similar pattern, but English requires 'such' before nouns and 'so' before adjectives."},
          {id:"wo023",type:"error",q:"He speaks English very fluent.",a:"He speaks English very fluently.",exp:"Adverbs modify verbs: 'speaks fluently' (not 'fluent'). Chinese doesn't distinguish adjectives from adverbs in form — 流利 (liuli) works for both. English adds '-ly'."},
          {id:"wo024",type:"mc",q:"Which word order is correct for a negative sentence?",options:["I don't never go there.","I never don't go there.","I never go there.","Never I go there."],a:2,exp:"English uses single negation: 'I never go' or 'I don't ever go'. Double negatives ('don't never') are non-standard. Chinese 我从来不去 uses 从来不 (double negative meaning), but English uses only one."},
          {id:"wo025",type:"error",q:"My every student passed the exam.",a:"Every one of my students passed the exam.",exp:"Chinese 我每个学生 puts the possessive before 'every'. English: 'every one of my students' or 'all my students'. Never 'my every student'. This word order doesn't exist in English."},
          {id:"wo026",type:"fill",q:"She asked me ___ I ___ available for a meeting on Friday.",a:"whether ... was",exp:"Indirect yes/no question: 'whether/if + statement order'. Chinese 她问我周五是否有空 uses 是否 (shifou) similarly. Note: 'was' not 'am' due to backshift after 'asked'."},
          {id:"wo027",type:"error",q:"I have a very big pressure at work recently.",a:"I have been under a lot of pressure at work recently.",exp:"Chinese 我有很大的压力 translates literally as 'I have big pressure'. English says 'be under pressure'. Also 'a lot of pressure' not 'a big pressure' — pressure is uncountable."},
          {id:"wo028",type:"mc",q:"Choose the correct word order for 'enough'.",options:["She is enough experienced to lead the team.","She is experienced enough to lead the team.","She is enough of experienced to lead the team.","Enough she is experienced to lead the team."],a:1,exp:"'Enough' goes AFTER adjectives: 'experienced enough'. But BEFORE nouns: 'enough experience'. Chinese 她够有经验 puts 够 (gou) before the adjective, causing the wrong order."},
          {id:"wo029",type:"error",q:"This kind of situation often will happen in schools.",a:"This kind of situation will often happen in schools.",exp:"Frequency adverbs go AFTER the first auxiliary: 'will often happen'. Chinese 经常会发生 puts the adverb before the modal. English: modal + adverb + main verb."},
          {id:"wo030",type:"fill",q:"The reason ___ she left ___ that she received a better offer.",a:"why ... was",exp:"'The reason why...was that...' — standard pattern. Chinese 她离开的原因是 follows a similar logic. Note: 'The reason is because' is considered redundant — use 'The reason is that'."},
          {id:"wo031",type:"error",q:"She each day practices piano for two hours.",a:"She practises piano for two hours each day.",exp:"Time expressions ('each day') go at the END in English. Chinese 她每天练两小时钢琴 puts 每天 (every day) after the subject. Note Australian spelling: 'practises' (verb)."},
          {id:"wo032",type:"error",q:"I think this not is a good idea.",a:"I don't think this is a good idea.",exp:"Chinese negative transfer: 我觉得这不是好主意 negates the subordinate clause. English typically negates the main verb: 'I don't think' (negative raising). Not 'I think this not is'."},
          {id:"wo033",type:"open",q:"Rewrite these Chinglish sentences in natural English: '1. This movie I already watched. 2. Because tired, so I went home. 3. He very like swimming. 4. My teacher she is kind.'",a:"1. I have already watched this movie. 2. Because I was tired, I went home. OR I was tired, so I went home. 3. He really likes swimming. 4. My teacher is kind.",exp:"Four classic Chinglish patterns: topic-fronting, double connectors, 'very' + verb, and double subjects. Each requires restructuring to standard English word order."},
          {id:"wo034",type:"fill",q:"She ___ only speaks Mandarin ___ also speaks Cantonese and English.",a:"not ... but",exp:"'Not only...but also': 'She not only speaks Mandarin but also speaks Cantonese.' Chinese 不但...而且 follows the same paired structure. The verb repeats in both clauses."},
          {id:"wo035",type:"error",q:"I more and more like living in Australia.",a:"I like living in Australia more and more.",exp:"'More and more' goes at the END of the clause. Chinese 越来越喜欢 puts it before the verb. English: 'like something more and more' or 'increasingly like'."},
          {id:"wo036",type:"mc",q:"Which sentence has correct English word order for 'also'?",options:["Also I like teaching science.","I also like teaching science.","I like also teaching science.","I like teaching also science."],a:1,exp:"'Also' goes BEFORE the main verb (but AFTER 'be'): 'I also like'. Chinese 我也喜欢 puts 也 (ye) before the verb, which happens to match here. But with 'be': 'She is also a teacher.'"},
          {id:"wo037",type:"error",q:"Do you know where can I find the IT office?",a:"Do you know where I can find the IT office?",exp:"Embedded question = statement order: 'where I can find'. The 'Do you know' already signals a question. Chinese word order doesn't change for direct vs indirect questions."},
          {id:"wo038",type:"fill",q:"He asked me ___ I ___ finished the report ___.",a:"if ... had ... yet",exp:"Indirect yes/no question with backshift: 'if I had finished'. 'Yet' goes at the end in questions/negatives. Chinese 他问我是否已经完成了报告."},
          {id:"wo039",type:"error",q:"I last night at the restaurant with my friends ate dinner.",a:"I ate dinner with my friends at the restaurant last night.",exp:"English order: S + V + O + companion + place + time. Chinese order: S + time + place + companion + V + O. 我昨晚在餐厅和朋友吃了晚饭 = completely different word order."},
          {id:"wo040",type:"error",q:"Tomorrow morning 9 o'clock I have a meeting at the school.",a:"I have a meeting at the school at 9 o'clock tomorrow morning.",exp:"Chinese puts time BEFORE everything: 明天早上九点我开会. English: Subject + Verb + Object + Place + Time. Time at the end, with most specific first: 'at 9 o'clock tomorrow morning'."}
        ]
      },      {
        id: "countable-uncountable",
        title: "Countable vs Uncountable Nouns",
        theory: "Chinese nouns do not distinguish countable from uncountable. All Chinese nouns require a measure word (量词 liangci). English uses 'a/an' for countable singulars and no article for uncountables. Common errors: 'informations', 'homeworks', 'furnitures', 'advices', 'equipments', 'feedbacks'.",
        exercises: [
          {id:"cu001",type:"error",q:"Can you give me some advices about my career?",a:"Can you give me some advice about my career?",exp:"'Advice' is uncountable — never 'advices'. Chinese 建议 (jianyi) can be counted with 条 (tiao), but English has no plural. Use 'a piece of advice' for one item."},
          {id:"cu002",type:"mc",q:"Which sentence is correct?",options:["I have many homeworks to do tonight.","I have a lot of homework to do tonight.","I have three homeworks to do tonight.","I have a homework to do tonight."],a:1,exp:"'Homework' is uncountable — never 'homeworks', 'a homework', or 'many homeworks'. Use 'a lot of homework' or 'homework tasks/assignments' if you need to count."},
          {id:"cu003",type:"error",q:"We need to buy new equipments for the science lab.",a:"We need to buy new equipment for the science lab.",exp:"'Equipment' is uncountable — never 'equipments'. Chinese 设备 (shebei) can be counted with 台/件. Use 'pieces of equipment' or 'items of equipment' to count."},
          {id:"cu004",type:"fill",q:"She gave me some useful ___ (information) and several ___ (suggestion).",a:"information ... suggestions",exp:"'Information' = uncountable (no change). 'Suggestions' = countable (add -s). Knowing which nouns are uncountable in English is critical — there is no pattern, only memorisation."},
          {id:"cu005",type:"error",q:"I have many furnitures in my apartment.",a:"I have a lot of furniture in my apartment.",exp:"'Furniture' is uncountable — never 'furnitures'. Chinese 家具 (jiaju) can be counted with 件. Use 'pieces of furniture' or 'items of furniture'. 'Many' = countable only; use 'a lot of' for uncountable."},
          {id:"cu006",type:"mc",q:"Which noun is UNCOUNTABLE in English?",options:["idea","luggage","suggestion","job"],a:1,exp:"'Luggage' is uncountable — never 'luggages' or 'a luggage'. Chinese 行李 (xingli) uses 件 as a measure word. Use 'a piece of luggage' or 'pieces of luggage'."},
          {id:"cu007",type:"error",q:"The teacher gave us many feedbacks on our essays.",a:"The teacher gave us a lot of feedback on our essays.",exp:"'Feedback' is uncountable — never 'feedbacks'. Chinese 反馈 (fankui) can be counted. Use 'a lot of feedback' or 'pieces of feedback'. 'Many' requires countable nouns."},
          {id:"cu008",type:"fill",q:"We had ___ (much/many) rain last month but not ___ (much/many) sunny days.",a:"much ... many",exp:"'Much' + uncountable ('much rain'). 'Many' + countable plural ('many days'). Chinese 很多 (henduo) covers both meanings without distinguishing."},
          {id:"cu009",type:"error",q:"She has a lot of experiences in teaching English.",a:"She has a lot of experience in teaching English.",exp:"'Experience' (general ability) is uncountable. But 'experiences' (individual events) IS countable: 'She had many interesting experiences in Japan.' Context determines which usage."},
          {id:"cu010",type:"fill",q:"I need to do some ___ (research) and read a few ___ (article) before the meeting.",a:"research ... articles",exp:"'Research' = uncountable (never 'researches' for the activity). 'Articles' = countable. Note: 'researches' can mean 'investigates' as a verb but not as a noun."},          {id:"cu011",type:"mc",q:"Which is the correct way to count 'bread'?",options:["three breads","three pieces of bread","three bread","a bread"],a:1,exp:"'Bread' is uncountable — use 'pieces of bread', 'slices of bread', or 'loaves of bread'. Chinese 三块面包 uses the measure word 块, but English uses 'pieces/slices/loaves of'."},
          {id:"cu012",type:"error",q:"She made a lot of progresses in her English this term.",a:"She made a lot of progress in her English this term.",exp:"'Progress' is uncountable — never 'progresses'. Chinese 进步 (jinbu) can be counted. Use 'made progress', 'made a lot of progress', or 'made significant progress'."},
          {id:"cu013",type:"fill",q:"How ___ (much/many) money do you need? And how ___ (much/many) coins do you have?",a:"much ... many",exp:"'Money' = uncountable ('how much'). 'Coins' = countable ('how many'). Chinese 多少 (duoshao) covers both without distinction."},
          {id:"cu014",type:"error",q:"I need to buy some stationeries for the classroom.",a:"I need to buy some stationery for the classroom.",exp:"'Stationery' is uncountable — never 'stationeries'. Chinese 文具 (wenju) can be counted with 件. Use 'items of stationery' or 'stationery supplies' to specify individual items."},
          {id:"cu015",type:"mc",q:"Which pair is correct?",options:["Less students, less homework","Fewer students, less homework","Less students, fewer homework","Fewer students, fewer homework"],a:1,exp:"'Fewer' + countable ('fewer students'). 'Less' + uncountable ('less homework'). Chinese 更少 (gengsao) covers both. This fewer/less distinction is a common error even for native speakers."},
          {id:"cu016",type:"error",q:"Could you give me an information about the programme?",a:"Could you give me some information about the programme?",exp:"'Information' is uncountable — never 'an information'. Use 'some information', 'a piece of information', or 'a bit of information'. Chinese 一条信息 uses the measure word 条."},
          {id:"cu017",type:"fill",q:"The school needs more ___ (staff/staffs) and better ___ (facility/facilities).",a:"staff ... facilities",exp:"'Staff' is a collective noun — uncountable for the group (never 'staffs' for people). 'Facilities' = countable plural. Note: 'staff member' is countable: 'three staff members'."},
          {id:"cu018",type:"error",q:"I have an important news to share with the team.",a:"I have some important news to share with the team.",exp:"'News' is uncountable — never 'a news' or 'newses'. Chinese 一个消息 (yi ge xiaoxi) uses a measure word. Use 'some news', 'a piece of news', or 'an item of news'."},
          {id:"cu019",type:"mc",q:"Which nouns are ALL uncountable?",options:["traffic, knowledge, accommodation","traffic, book, accommodation","job, knowledge, furniture","advice, suggestion, homework"],a:0,exp:"'Traffic', 'knowledge', and 'accommodation' (Australian/British English) are all uncountable. 'Book', 'job', and 'suggestion' are countable. Note: American English may use 'accommodations' (plural)."},
          {id:"cu020",type:"fill",q:"She has ___ (little/few) patience and ___ (little/few) friends at work.",a:"little ... few",exp:"'Little' + uncountable ('little patience'). 'Few' + countable ('few friends'). Also: 'a little' = some (positive), 'little' = not much (negative). Same with 'a few' vs 'few'."},
          {id:"cu021",type:"error",q:"We bought several new softwares for the computer lab.",a:"We bought several new software programs for the computer lab.",exp:"'Software' is uncountable — never 'softwares'. Use 'software programs', 'software packages', or 'pieces of software' for individual items. Chinese 软件 (ruanjian) can be counted."},
          {id:"cu022",type:"fill",q:"There is too ___ (much/many) noise in the classroom and too ___ (much/many) distractions.",a:"much ... many",exp:"'Noise' = uncountable ('too much noise'). 'Distractions' = countable ('too many distractions'). Chinese 太多 covers both."},
          {id:"cu023",type:"error",q:"She gave me several useful informations about the job market.",a:"She gave me several useful pieces of information about the job market.",exp:"To count 'information', use 'pieces of': 'several pieces of information'. Never 'informations'. The adjective 'useful' goes before 'pieces'."},
          {id:"cu024",type:"mc",q:"'Work' can be countable or uncountable. Which is correct?",options:["I have many works to finish. (= tasks)","I have a lot of work to finish. (= tasks)","I have much works to finish. (= tasks)","I have works to finish. (= tasks)"],a:1,exp:"'Work' (general labour/tasks) is uncountable: 'a lot of work'. 'Works' = artistic works or engineering works: 'the works of Shakespeare'. For tasks, say 'a lot of work' or 'many tasks'."},
          {id:"cu025",type:"error",q:"I need to pack all my luggages before the flight.",a:"I need to pack all my luggage before the flight.",exp:"'Luggage' is uncountable — never 'luggages'. Also never 'a luggage'. Chinese 行李 uses 件 as a measure word. Use 'pieces of luggage' or 'bags' to count."},
          {id:"cu026",type:"fill",q:"She has ___ (a/zero) great knowledge of Australian history and ___ (a/zero) strong understanding of the curriculum.",a:"a ... a",exp:"'A great knowledge' and 'a strong understanding' — when modified by an adjective, these abstract nouns take 'a'. Without the adjective: 'She has knowledge' (zero article). This is a subtle rule."},
          {id:"cu027",type:"error",q:"The accommodation in Sydney is expensive. We need to find cheaper accommodations.",a:"The accommodation in Sydney is expensive. We need to find cheaper accommodation.",exp:"In Australian/British English, 'accommodation' is uncountable. Never 'accommodations'. American English does use 'accommodations'. Use 'cheaper accommodation' or 'more affordable places to stay'."},
          {id:"cu028",type:"mc",q:"Which is correct for counting 'paper'?",options:["Give me two papers. (= sheets)","Give me two pieces of paper. (= sheets)","Give me two paper. (= sheets)","Give me paper two. (= sheets)"],a:1,exp:"'Paper' (material) is uncountable: 'two pieces of paper'. But 'papers' = documents or academic papers: 'research papers'. The meaning changes with countability."},
          {id:"cu029",type:"fill",q:"There is not ___ (much/many) evidence to support the claim, and only ___ (a few/a little) data points are available.",a:"much ... a few",exp:"'Evidence' = uncountable ('much evidence'). 'Data points' = countable ('a few data points'). Note: 'data' can be treated as uncountable in modern usage."},
          {id:"cu030",type:"open",q:"Correct all countability errors: 'I need some advices. Also please give me informations about the equipments. I have many homeworks and several researches to complete.'",a:"I need some advice. Also please give me some information about the equipment. I have a lot of homework and several research projects to complete.",exp:"Five uncountable nouns corrected: advice (not advices), information (not informations), equipment (not equipments), homework (not homeworks), research (not researches — use 'research projects' to count)."},
          {id:"cu031",type:"error",q:"She bought new furnitures for the staffroom: two couches and a table.",a:"She bought new furniture for the staffroom: two couches and a table.",exp:"'Furniture' is uncountable even when listing specific items. The individual items (couches, table) are countable, but 'furniture' as a category is not."},
          {id:"cu032",type:"fill",q:"How ___ (much/many) time do we have? And how ___ (much/many) tasks are left?",a:"much ... many",exp:"'Time' (in general) = uncountable ('how much time'). 'Tasks' = countable ('how many tasks'). But note: 'times' (occasions) IS countable: 'How many times have you visited?'"}
        ]
      },      {
        id: "verb-patterns-collocations",
        title: "Verb Patterns & Collocations",
        theory: "Many Chinese speakers use direct translations that produce unnatural English collocations. Common examples: 'open the light' (turn on, from 开灯 kai deng), 'eat medicine' (take medicine, from 吃药 chi yao), 'play computer' (use the computer, from 玩电脑 wan diannao), 'discuss about' (discuss, no preposition needed).",
        exercises: [
          {id:"vc001",type:"error",q:"Please open the light. It is too dark in here.",a:"Please turn on the light. It is too dark in here.",exp:"Chinese 开灯 (kai deng) literally means 'open light'. English: 'turn on the light'. Also: 'turn off' (关), 'turn up/down' (调高/调低). 'Open' is only for doors, windows, books, etc."},
          {id:"vc002",type:"error",q:"I need to eat some medicine for my headache.",a:"I need to take some medicine for my headache.",exp:"Chinese 吃药 (chi yao) literally means 'eat medicine'. English: 'take medicine'. Also: 'take a tablet', 'take a pill'. 'Eat' is only for food."},
          {id:"vc003",type:"mc",q:"Which is the correct collocation?",options:["play computer","use the computer","open the computer","hit the computer"],a:1,exp:"Chinese 玩电脑 (wan diannao) = 'play computer'. English: 'use the computer'. 'Play' is for games/sports/instruments. You can 'play a computer game' but not 'play computer'."},
          {id:"vc004",type:"error",q:"She closed the light and went to bed.",a:"She turned off the light and went to bed.",exp:"Chinese 关灯 (guan deng) = 'close light'. English: 'turn off the light'. 'Close' is for doors, windows, books, eyes. Light switches are 'turned on/off'."},
          {id:"vc005",type:"fill",q:"He ___ a shower, ___ breakfast, and then ___ the bus to work.",a:"had ... had ... caught",exp:"'Have a shower' (not 'wash shower'). 'Have breakfast' (not 'eat breakfast' — both OK but 'have' is more natural). 'Catch the bus' (not 'take the bus' — both OK, 'catch' implies timing)."},
          {id:"vc006",type:"error",q:"I want to see a look at your essay before you submit it.",a:"I want to have a look at your essay before you submit it.",exp:"Chinese 看一看 = 'see a look'. English: 'have a look', 'take a look'. 'See' doesn't collocate with 'a look'. This is a fixed expression."},
          {id:"vc007",type:"mc",q:"Which collocation is natural English?",options:["make homework","do homework","write homework","produce homework"],a:1,exp:"'Do homework' (not 'make homework'). The do/make distinction is difficult: 'do' = tasks and activities (do homework, do the dishes, do exercise). 'Make' = create something (make dinner, make a decision)."},
          {id:"vc008",type:"error",q:"She made an exam yesterday and got a high mark.",a:"She took an exam yesterday and got a high mark.",exp:"'Take an exam' (not 'make an exam'). The teacher 'sets/gives' the exam; the student 'takes/sits' the exam. Chinese 做考试 or 考试 doesn't distinguish these roles."},
          {id:"vc009",type:"fill",q:"Could you ___ me a favour and ___ a photo of the whiteboard?",a:"do ... take",exp:"'Do someone a favour' (not 'make'). 'Take a photo/picture' (not 'make a photo' — though some European languages use 'make'). Chinese 拍照 (pai zhao) = 'take a photo'."},
          {id:"vc010",type:"error",q:"I will follow my dream and do more efforts to succeed.",a:"I will follow my dream and make more effort to succeed.",exp:"'Make an effort/efforts' (not 'do effort'). Chinese 做努力 (zuo nuli) uses 做 which usually maps to 'do'. But this is a 'make' collocation: 'make an effort', 'make progress'."},          {id:"vc011",type:"error",q:"She raised a question and the teacher gave her a satisfy answer.",a:"She raised a question and the teacher gave her a satisfactory answer.",exp:"'Satisfactory' is the adjective form. Chinese 满意的 (manyi de) doesn't change form. English: 'satisfy' (verb), 'satisfactory/satisfying' (adjective), 'satisfaction' (noun)."},
          {id:"vc012",type:"mc",q:"Which phrase means 'to make progress'?",options:["go forward","make headway","walk ahead","move progress"],a:1,exp:"'Make headway' = make progress. Also: 'make strides', 'make progress'. Never 'move progress' or 'do progress'. Chinese 取得进展 (qude jinzhan) = 'obtain progress'."},
          {id:"vc013",type:"fill",q:"She ___ a decision to ___ a complaint about the noisy construction.",a:"made ... lodge",exp:"'Make a decision' (not 'do'). 'Lodge a complaint' or 'make a complaint' (formal). Chinese 做决定 uses 做 = 'make'. 'Lodge' is the formal verb for official complaints."},
          {id:"vc014",type:"error",q:"He said he will give me a call to discuss about the schedule.",a:"He said he would give me a call to discuss the schedule.",exp:"Two errors: 'would' (backshift after 'said'). 'Discuss' takes a direct object — never 'discuss about'. Chinese 讨论关于 (taolun guanyu) includes 'about'."},
          {id:"vc015",type:"mc",q:"Which is correct: 'make' or 'do'?",options:["She did a mistake in the report.","She made a mistake in the report.","She created a mistake in the report.","She performed a mistake in the report."],a:1,exp:"'Make a mistake' (never 'do a mistake'). Also: 'make an error', 'make a blunder'. The make/do distinction is one of the hardest collocations for Chinese speakers."},
          {id:"vc016",type:"error",q:"I want to improve my English level.",a:"I want to improve my English.",exp:"'Improve my English' — 'level' is unnecessary and sounds Chinglish. Chinese 提高英语水平 (tigao yingyu shuiping) includes 水平 (level). English just says 'improve my English' or 'improve my English skills'."},
          {id:"vc017",type:"fill",q:"The students need to ___ attention in class and ___ notes during the lecture.",a:"pay ... take",exp:"'Pay attention' (not 'give attention'). 'Take notes' (not 'make notes' — though 'make notes' is acceptable in British English). Chinese 注意 and 做笔记 use different verbs."},
          {id:"vc018",type:"error",q:"Can you borrow me your pen for a minute?",a:"Can you lend me your pen for a minute?",exp:"'Lend' = give temporarily (the giver's action). 'Borrow' = take temporarily (the receiver's action). Chinese 借 (jie) covers both directions. 'Can you lend me?' or 'Can I borrow your?'"},
          {id:"vc019",type:"mc",q:"Complete: 'We need to ___ a meeting to discuss the issue.'",options:["open","hold","make","do"],a:1,exp:"'Hold a meeting' = organise and conduct. Also: 'arrange a meeting', 'call a meeting'. Chinese 开会 (kai hui) literally means 'open meeting' — but English uses 'hold'."},
          {id:"vc020",type:"fill",q:"She ___ a mistake on the form and had to ___ an apology to the parent.",a:"made ... make",exp:"'Made a mistake'. 'Make an apology' (formal) or 'apologise' (verb form). Both 'make' — this is a pattern: 'make a mistake', 'make an apology', 'make a suggestion', 'make a complaint'."},
          {id:"vc021",type:"error",q:"The student said a lie to the teacher about why he was late.",a:"The student told a lie to the teacher about why he was late.",exp:"'Tell a lie' (not 'say a lie'). Say/tell distinction: 'say' + words/sentences. 'Tell' + people or stories/lies/truths/jokes. Chinese 说谎 (shuo huang) uses 说 which maps to 'say', causing this error."},
          {id:"vc022",type:"fill",q:"I ___ a cold last week and had to ___ time off work.",a:"caught ... take",exp:"'Catch a cold' (not 'get a cold' — though 'get' is informal OK). 'Take time off' (not 'have time off' in this context). Illness collocations: 'catch a cold', 'come down with the flu'."},
          {id:"vc023",type:"error",q:"She suggested me to apply for the position.",a:"She suggested that I apply for the position.",exp:"'Suggest that someone do something' (subjunctive) or 'suggest doing something'. Never 'suggest someone to do'. Chinese 她建议我申请 places the person directly after suggest, causing this error."},
          {id:"vc024",type:"mc",q:"Which is the natural collocation?",options:["do your best","make your best","try your best","give your best"],a:0,exp:"'Do your best' is the most common. 'Try your best' is also acceptable. Chinese 尽力 (jinli) = 'exhaust strength'. 'Give it your best shot' is informal. 'Make your best' is incorrect."},
          {id:"vc025",type:"error",q:"Let me give you some suggest about your teaching practice.",a:"Let me give you some suggestions about your teaching practice.",exp:"'Suggestion/suggestions' (noun, countable). 'Suggest' is a verb. Chinese doesn't always distinguish noun/verb forms. Also correct: 'Let me make a suggestion.'"},
          {id:"vc026",type:"fill",q:"We ___ an agreement after the negotiation and ___ hands to seal the deal.",a:"reached ... shook",exp:"'Reach an agreement' (not 'get' or 'make'). 'Shook hands' (past of 'shake hands'). Chinese 达成协议 = 'reach agreement'. 'Shake hands' = 握手 (wo shou)."},
          {id:"vc027",type:"error",q:"I must to finish this report before the deadline.",a:"I must finish this report before the deadline.",exp:"Modal verbs (must, can, should, will, may) are NEVER followed by 'to'. This is a very common Chinese-speaker error. Chinese 我必须完成 doesn't have an equivalent of 'to'."},
          {id:"vc028",type:"mc",q:"Which verb collocates with 'responsibility'?",options:["do responsibility","make responsibility","take responsibility","have responsibility"],a:2,exp:"'Take responsibility' = accept that it is your duty. Also: 'assume responsibility', 'bear responsibility'. Chinese 承担责任 (chengdan zeren) maps well to 'take/bear responsibility'."},
          {id:"vc029",type:"fill",q:"He ___ a deep breath, ___ his composure, and began his presentation.",a:"took ... regained",exp:"'Take a deep breath' (not 'make'). 'Regain composure' (not 'get back calm'). These verb-noun collocations must be memorised — direct translation from Chinese rarely works."},
          {id:"vc030",type:"open",q:"Replace the Chinglish collocations with natural English: '1. Please close the computer. 2. I want to eat medicine. 3. She made a phone to her mother. 4. He opened the TV. 5. I will do my best effort.'",a:"1. Please shut down the computer. 2. I want to take some medicine. 3. She made a phone call to her mother. 4. He turned on the TV. 5. I will do my best.",exp:"Five Chinglish collocations corrected: shut down (not close) for computers, take (not eat) medicine, make a phone call (not make a phone), turn on (not open) electronics, do my best (not do best effort)."},
          {id:"vc031",type:"error",q:"She is very boring with the long meeting.",a:"She is very bored with the long meeting.",exp:"'-Ed' adjectives describe feelings: 'bored' (how she feels). '-Ing' adjectives describe things: 'boring meeting' (the meeting causes boredom). Chinese 无聊 covers both meanings, causing frequent confusion."},
          {id:"vc032",type:"fill",q:"The teacher ___ the roll at the start of each lesson and ___ attendance records.",a:"marks ... keeps",exp:"'Mark the roll' = take attendance (Australian English). 'Keep records' = maintain records. Chinese 点名 (dian ming) = 'mark names'. These are specific Australian school collocations."}
        ]
      }
    ]
  };
  // ============================================================
  // MODULE 7: INTERVIEW SKILLS FOR TEACHING POSITIONS
  // ============================================================
  WORKPLACE_ENGLISH.interviewSkills = {
    title: "Interview Skills for Teaching Positions",
    sections: [
      {
        id: "interview-openers",
        title: "First Impressions & Self-Introduction",
        theory: "Australian interviews start with small talk ('How was your trip here?', 'Would you like some water?'). Your self-introduction should be 60-90 seconds, covering your background, teaching philosophy, and why you are excited about this role. Chinese speakers sometimes give overly humble introductions ('My English is not very good') — avoid self-deprecation.",
        exercises: [
          {id:"iv001",type:"mc",q:"The panel says 'How was your trip here today?' What is the best response?",options:["It was terrible. The traffic was awful.","Fine. Can we start the interview?","It was good, thank you. I actually drove past the school yesterday to make sure I knew where to go.","I do not want to waste time talking about this."],a:2,exp:"Small talk builds rapport. Show you are prepared (scouted the location) and friendly. Don't be negative (option 0) or dismissive (option 1 and 3). Australian interviews value warmth."},
          {id:"iv002",type:"error",q:"My English is not very good, but I will try my best to answer your questions.",a:"I'm happy to be here. Let me tell you about my background and my passion for teaching.",exp:"Never self-deprecate in an interview. Chinese modesty (谦虚 qianxu) is a virtue in Chinese culture, but in Australian interviews it signals lack of confidence. Lead with enthusiasm."},
          {id:"iv003",type:"fill",q:"Good morning. Thank you for ___ me for this interview. I'm really ___ about the opportunity to join your school.",a:"inviting ... excited",exp:"'Thank you for inviting me' shows gratitude. 'Excited about' shows enthusiasm. This is a strong opening — professional, warm, and confident without being arrogant."},
          {id:"iv004",type:"mc",q:"Which self-introduction opening is most effective?",options:["I graduated from university in 2019 and then I did a few different jobs...","I have been passionate about education since my own school days, and I bring five years of classroom experience to this role.","My name is [name] and I am from China. I came to Australia in 2015.","Let me start by saying I am very nervous."],a:1,exp:"Lead with your VALUE — what you bring. Don't start with chronological biography (option 0) or origin story (option 2). Never mention nervousness (option 3)."},
          {id:"iv005",type:"fill",q:"I have ___ years of teaching experience, specialising in ___ and ___.",a:"five ... Technology ... IST",exp:"State your experience clearly with specifics. Use the Australian subject names: 'Technology' (not 'tech class'), 'Information and Software Technology' or 'IST'. Specificity builds credibility."},
          {id:"iv006",type:"error",q:"I think maybe I could be a good fit for this role if you give me a chance.",a:"I am confident that my skills and experience make me a strong fit for this role.",exp:"Hedging ('I think maybe') and pleading ('give me a chance') sound weak. Be direct and confident. Chinese speakers often soften statements out of politeness, but interviews reward assertiveness."},
          {id:"iv007",type:"mc",q:"The panel offers you water. What should you do?",options:["Decline — accepting anything seems greedy.","Accept graciously — it is a normal courtesy.","Ask for tea or coffee instead.","Ignore the offer and start your introduction."],a:1,exp:"Accept the water. It is a normal Australian courtesy. Having water also gives you a moment to pause and collect thoughts during the interview. Declining seems overly formal."},
          {id:"iv008",type:"fill",q:"What drew me to this school in particular is your commitment to ___ and your strong ___.",a:"student wellbeing ... community partnerships",exp:"Research the school before the interview. Reference specific things: their values, programmes, achievements. Generic answers ('it is a good school') don't impress. Check the school's website and annual report."},
          {id:"iv009",type:"open",q:"Write a 60-second self-introduction for a Technology teacher interview at a public high school in western Sydney.",a:"Good morning. Thank you for having me today. My name is [name] and I am a passionate Technology and IST teacher with experience in project-based learning and digital technologies. I completed my teaching qualification at [university] and have spent the past [X] years teaching Years 7 to 10 in diverse school settings. What excites me about teaching is seeing students develop real-world problem-solving skills. I am particularly drawn to this school because of your commitment to student engagement and your strong STEM programme. I believe my experience with differentiated instruction and my background in data and design would be a genuine asset to your faculty.",exp:"A strong self-introduction covers: who you are, your qualifications, your experience, your teaching passion, and why THIS school. 60-90 seconds, practised but not robotic."},
          {id:"iv010",type:"error",q:"I am not sure I am the best candidate, but I have some experience in teaching.",a:"I have solid experience in teaching Technology and IST, and I am confident I can contribute to your team.",exp:"Remove self-doubt and hedging. Replace 'not sure' with confidence. Replace 'some experience' with specifics. Chinese-speaking candidates often understate qualifications."},          {id:"iv011",type:"fill",q:"I noticed from your school's website that you recently launched a ___ programme. I would love to contribute to that ___.",a:"STEM ... initiative",exp:"Showing you researched the school impresses panels. Use words like 'initiative', 'programme', 'project' to sound professional. This shows genuine interest, not just applying everywhere."},
          {id:"iv012",type:"mc",q:"How should you address the interview panel?",options:["Hey guys, thanks for having me.","Good morning. Thank you for the opportunity to meet with you today.","Hello teacher. I am here for the job.","Greetings, esteemed panel members."],a:1,exp:"Professional but warm. 'Good morning' + gratitude is perfect. 'Hey guys' is too casual. 'Hello teacher' is Chinglish. Option 3 is overly formal and sounds unnatural in Australia."},
          {id:"iv013",type:"error",q:"I want this job because the salary is good and the holidays are long.",a:"I want this role because I am passionate about supporting young people and I believe in the school's approach to student-centred learning.",exp:"Never mention salary or holidays as motivation. Focus on passion for teaching, the school's values, and how you can contribute. Salary questions come later, if at all."},
          {id:"iv014",type:"fill",q:"One of my strengths is my ability to ___ with students from diverse ___ backgrounds.",a:"connect ... cultural",exp:"'Connect with students' = build relationships. 'Diverse cultural backgrounds' = important in Australian schools, especially western Sydney. This shows cultural competence."},
          {id:"iv015",type:"mc",q:"What should you do while waiting in the reception area before the interview?",options:["Check your phone and scroll social media.","Observe the school environment, look at notice boards, and review your notes.","Chat loudly on the phone with a friend.","Pace nervously back and forth."],a:1,exp:"Use waiting time productively: observe the school culture, check notice boards (school values, recent events), and review key points. You might reference something you noticed during the interview."},
          {id:"iv016",type:"fill",q:"I believe in creating a classroom environment that is both ___ and ___, where every student feels safe to take risks.",a:"supportive ... challenging",exp:"'Supportive and challenging' shows balance — you care about wellbeing AND academic rigour. Australian education values both. This phrase works well in teaching philosophy statements."},
          {id:"iv017",type:"error",q:"I can teach any subject. I am flexible and will do whatever you need.",a:"My teaching strengths are in Technology and IST. I also have experience supporting literacy across the curriculum and am happy to contribute to other areas where the school has needs.",exp:"Being too flexible sounds desperate. Show specific expertise, then demonstrate willingness to contribute beyond your area. Panels want specialists who are also team players."},
          {id:"iv018",type:"mc",q:"When should you arrive for an interview?",options:["Exactly on time.","5-10 minutes early.","30 minutes early.","It does not matter as long as you arrive."],a:1,exp:"5-10 minutes early is ideal. It shows punctuality without creating awkwardness. Arriving too early can be inconvenient for the school. Being exactly on time leaves no buffer for unexpected delays."},
          {id:"iv019",type:"fill",q:"Coming from a bilingual background, I bring a unique ___ to understanding the challenges faced by ___ learners.",a:"perspective ... EAL/D",exp:"Frame your bilingualism as an ASSET, not a limitation. 'EAL/D' = English as an Additional Language or Dialect — the Australian term. This shows you understand the Australian education context."},
          {id:"iv020",type:"error",q:"I do not have much experience yet, but I am a fast learner.",a:"While I am early in my teaching career, I have already demonstrated strong results in my practicum placements and I am eager to continue developing my practice.",exp:"Reframe inexperience positively. 'Early in my career' is better than 'not much experience'. Reference concrete evidence from practicums. Show a growth mindset."},
          {id:"iv021",type:"open",q:"Write a response to: 'Tell us a bit about yourself and why you applied for this position.'",a:"Thank you for asking. I am a Technology and IST teacher with a background in design and digital systems. I completed my Master of Teaching at [university] and during my practicum placements I discovered my passion for project-based learning and helping students develop real-world skills. What attracted me to this school specifically is your focus on innovation and your commitment to supporting a diverse student community. I believe my experience with differentiated instruction and my ability to connect with students from various cultural backgrounds would allow me to make a meaningful contribution to your faculty.",exp:"Structure: Background, qualification, passion, why this school, what you offer. Specific, confident, and shows research about the school. Approximately 60-90 seconds when spoken."},
          {id:"iv022",type:"fill",q:"I have strong skills in ___ management and I am experienced in using ___ to enhance student engagement.",a:"classroom ... technology",exp:"Two key selling points for any teaching role. 'Classroom management' is the #1 concern for school leaders hiring. 'Technology for engagement' is highly valued in modern Australian schools."},
          {id:"iv023",type:"mc",q:"Which body language is most appropriate during an Australian job interview?",options:["Avoid eye contact to show respect.","Maintain natural eye contact, sit upright, and smile warmly.","Cross your arms to look confident.","Look down at your notes the entire time."],a:1,exp:"Natural eye contact shows confidence and honesty in Australian culture. Chinese culture sometimes values avoiding direct eye contact with authority, but Australian interviews expect it. Smile warmly."},
          {id:"iv024",type:"error",q:"I have experience in making students to be quiet and follow rules strictly.",a:"I have experience in creating a positive learning environment where students are engaged and respectful.",exp:"'Making students be quiet' sounds authoritarian. Australian schools value positive behaviour management. Reframe: 'positive learning environment', 'engaged', 'respectful'. Show modern pedagogy."},
          {id:"iv025",type:"fill",q:"My teaching philosophy centres on the belief that every student ___ to learn and that ___ instruction is key to meeting diverse needs.",a:"deserves the opportunity ... differentiated",exp:"'Every student deserves the opportunity to learn' — inclusive philosophy. 'Differentiated instruction' — the Australian education buzzword for adapting teaching to different levels. Essential vocabulary."},
          {id:"iv026",type:"mc",q:"You are asked an unexpected question you do not know the answer to. What is the best response?",options:["I don't know. Next question please.","That's a great question. I haven't encountered that specific situation, but let me think about how I would approach it...","I am not prepared for that question. Sorry.","Can you ask me something easier?"],a:1,exp:"Acknowledge the question, be honest, and then think aloud. 'Let me think about how I would approach it' shows problem-solving. Panels expect you to think on your feet — they don't expect perfect answers."},
          {id:"iv027",type:"fill",q:"I am committed to ___ professional development and staying current with best ___ in education.",a:"ongoing ... practice",exp:"'Ongoing professional development' = continuous learning. 'Best practice' = the most effective methods. These phrases signal that you are growth-oriented, which panels love."},
          {id:"iv028",type:"error",q:"In China we have a saying: 'the teacher opens the door, but you enter by yourself'. This is my philosophy.",a:"My teaching philosophy focuses on student agency — I create the conditions for learning and empower students to take ownership of their educational journey.",exp:"Cultural proverbs can be charming, but rephrase them in educational language the panel understands. 'Student agency', 'take ownership', 'conditions for learning' are the Australian equivalents."},
          {id:"iv029",type:"open",q:"Write a response to the small-talk question: 'Did you find us OK? The area can be a bit tricky to navigate.'",a:"Yes, I found you without any trouble, thank you. I actually drove past the school over the weekend to check the route. It is a lovely area — I noticed the park next door, which must be great for outdoor learning activities.",exp:"Shows preparation (drove past over the weekend), positivity about the area, and ties the observation back to teaching (outdoor learning). Natural, warm, and professional."},
          {id:"iv030",type:"fill",q:"I look forward to the opportunity to ___ to your school community and to ___ alongside your talented teaching staff.",a:"contribute ... collaborate",exp:"'Contribute to' and 'collaborate alongside' are strong closing phrases. They show you see yourself as part of a team, not a lone operator. Teamwork is highly valued in Australian schools."}
        ]
      },      {
        id: "interview-behavioural",
        title: "Behavioural Questions (STAR Method)",
        theory: "Australian interviews heavily use behavioural questions: 'Tell me about a time when...'. Use the STAR method: Situation, Task, Action, Result. Be specific, use past tense, quantify results where possible. Chinese speakers sometimes give vague or theoretical answers instead of specific examples.",
        exercises: [
          {id:"iv031",type:"mc",q:"What does STAR stand for in the interview context?",options:["Study, Test, Assess, Review","Situation, Task, Action, Result","Start, Think, Act, Respond","Strategy, Timeline, Achievement, Reflection"],a:1,exp:"STAR: Situation (context), Task (your responsibility), Action (what YOU did), Result (the outcome). This is the standard framework for answering behavioural questions in Australian interviews."},
          {id:"iv032",type:"error",q:"When students misbehave, I think it is important to be firm but fair.",a:"In my Year 8 class last term, a student was consistently disrupting lessons. I spoke to him privately, discovered he was struggling with the content, and set up a differentiated task for him. His behaviour improved significantly within two weeks.",exp:"The original is theoretical ('I think...'). Interviews want SPECIFIC examples with the STAR method. Name the year level, the situation, your action, and the result."},
          {id:"iv033",type:"fill",q:"During my practicum at ___ High School, I noticed that a group of Year ___ students were disengaged during reading activities.",a:"[School Name] ... 9",exp:"The Situation in STAR must be specific: name the school, the year level, the subject. Vague answers ('at a school I worked at') are unconvincing. Use real examples from your placements."},
          {id:"iv034",type:"mc",q:"Which is the strongest 'Action' statement in a STAR response?",options:["I tried to help the student.","I implemented a peer-mentoring system where high-achieving students supported struggling learners during collaborative tasks.","I told the student to work harder.","I felt bad for the student."],a:1,exp:"Option 1 is specific and describes a concrete strategy. 'Tried to help' is vague. 'Told them to work harder' shows poor pedagogy. 'Felt bad' is a feeling, not an action."},
          {id:"iv035",type:"fill",q:"As a result of this intervention, the student's engagement ___ noticeably and their assessment mark improved from a ___ to a ___.",a:"increased ... D ... B",exp:"The Result in STAR should be measurable. 'Increased noticeably' is good. Grade improvement (D to B) is specific evidence. Panels want to see IMPACT, not just effort."},
          {id:"iv036",type:"error",q:"I always handle difficult parents well. I am very good at communication.",a:"Last term, a parent emailed me concerned about their child's mark on a Technology project. I scheduled a phone call within 24 hours, explained the marking criteria, and offered a revision opportunity. The parent was satisfied and thanked me for my responsiveness.",exp:"Replace general claims ('I always handle well') with a SPECIFIC example using STAR. Show the Situation (parent concern), Task (respond professionally), Action (call, explain, offer revision), Result (satisfied parent)."},
          {id:"iv037",type:"mc",q:"'Tell me about a time you differentiated your teaching.' Which response uses STAR correctly?",options:["I believe differentiation is very important for all students.","In my Year 7 Technology class, I had students ranging from below grade to highly gifted. I designed three-tier activities for each lesson: a scaffolded version with sentence starters, a core task, and an extension challenge. As a result, all students could access the learning and my supervisor commended the approach.","I would use different worksheets for different students.","Differentiation means giving easier work to weaker students."],a:1,exp:"Option 1 uses STAR: Situation (Year 7, range of abilities), Task (implied: meet all needs), Action (three-tier activities), Result (all students accessed learning, supervisor commended). The others are theoretical."},
          {id:"iv038",type:"fill",q:"I recognised that the student was struggling, so I ___ a one-on-one conversation and together we ___ a support plan.",a:"initiated ... developed",exp:"Strong action verbs: 'initiated' (started proactively), 'developed' (created collaboratively). Use professional verbs in STAR responses, not casual ones like 'talked to' or 'made'."},
          {id:"iv039",type:"open",q:"Using the STAR method, write a response to: 'Tell me about a time you managed a challenging behaviour situation.'",a:"During my practicum at [School] High School, I had a Year 9 student who regularly refused to complete tasks and was disruptive to other learners. My task was to re-engage this student without escalating the conflict. I started by having a private conversation to understand the root cause — he was behind in literacy and felt embarrassed in front of peers. I then arranged modified tasks at his reading level and seated him with a supportive peer mentor. Within three weeks, he was completing tasks independently and his disruptions dropped from daily to almost none. His regular teacher commented that she had never seen him so engaged.",exp:"Full STAR: Situation (Year 9, disruptive student), Task (re-engage without escalation), Action (private chat, modified tasks, peer mentor), Result (independent work, reduced disruptions, teacher comment)."},
          {id:"iv040",type:"error",q:"In China, students are very respectful to teachers. I think Australian students should also be more respectful.",a:"I understand that classroom dynamics vary across cultures. In my experience teaching in Australian schools, I have found that building genuine relationships and earning student respect through consistent, fair practices works well. For example, during my practicum I built rapport by learning students' names quickly and showing genuine interest in their lives.",exp:"Comparing cultures negatively never works in an interview. Show you understand and VALUE the Australian context. Give a concrete example of how you adapted."},          {id:"iv041",type:"fill",q:"A key moment in my teaching career was when I ___ that a student's disruptive behaviour was actually a ___ for help.",a:"realised ... cry",exp:"'A cry for help' = a signal that someone is struggling. Showing emotional intelligence and insight impresses panels. It demonstrates you look beyond surface behaviour."},
          {id:"iv042",type:"mc",q:"'Describe a time you worked effectively as part of a team.' What is the panel assessing?",options:["Whether you can follow orders.","Your ability to collaborate, communicate, and contribute to shared goals.","Whether you prefer working alone.","Your leadership skills only."],a:1,exp:"Teamwork questions assess collaboration, communication, and willingness to share responsibility. Australian schools are team-based — faculty meetings, stage teams, co-planning. Show you are a team player."},
          {id:"iv043",type:"error",q:"I am very good at working with my colleagues. We have a good relationship.",a:"In my previous school, I collaborated with the Year 7 team to redesign the Technology scope and sequence. I contributed the digital literacy strand while a colleague handled engineering. We co-planned weekly and the resulting programme received positive feedback from the head teacher.",exp:"Replace vague claims with STAR. Name the team, your specific contribution, how you collaborated, and the outcome. 'Good relationship' tells the panel nothing concrete."},
          {id:"iv044",type:"fill",q:"I ___ the issue to my head teacher promptly and together we ___ a plan to support the student.",a:"escalated ... devised",exp:"'Escalated' = referred upward (professional term, not negative). 'Devised' = created/designed. Knowing when to escalate issues shows professionalism. You don't have to solve everything alone."},
          {id:"iv045",type:"mc",q:"What makes a weak STAR response?",options:["Using specific examples with measurable outcomes.","Giving a theoretical answer about what you 'would' do instead of what you actually did.","Describing your exact actions step by step.","Including the result and what you learned."],a:1,exp:"Theoretical answers ('I would...') are the #1 weakness. Panels want EVIDENCE of past behaviour: 'I did...' Chinese speakers sometimes answer with principles rather than stories because Chinese interviews differ."},
          {id:"iv046",type:"fill",q:"The result was that the student's attendance improved from ___% to ___%, and they successfully completed the term's assessment tasks.",a:"65 ... 90",exp:"Quantify results wherever possible: percentages, grades, attendance rates, behaviour referral numbers. 'Improved attendance' is good; '65% to 90%' is compelling evidence."},
          {id:"iv047",type:"error",q:"I think communication with parents is important. Teachers should contact parents regularly.",a:"Last term, I introduced a fortnightly parent update email for my Year 8 class. Each email included highlights of what we learned, upcoming assessments, and tips for supporting learning at home. Parent engagement at information evening increased from 30% to 55% after I started this practice.",exp:"STAR with quantified results. 'I introduced' (specific action), 'fortnightly emails' (consistent practice), and '30% to 55%' (measurable result). Theory alone won't win the role."},
          {id:"iv048",type:"open",q:"Using STAR, respond to: 'Give an example of how you have used data to improve student outcomes.'",a:"In my Year 10 IST class (Situation), I noticed that mid-term assessment data showed 40% of students scoring below expectations in the multimedia module (Task: identify and address the gap). I analysed the specific questions they struggled with and found that most errors related to file format and resolution concepts. I redesigned two lessons with hands-on activities using real image files, and created a visual reference sheet (Action). In the end-of-term assessment, the below-expectations rate dropped to 15%, and student feedback indicated they found the hands-on approach much clearer (Result).",exp:"Strong STAR with data: 40% below expectations, specific skill gap identified, concrete redesign action, measurable improvement to 15%. This demonstrates data literacy and responsive teaching."},
          {id:"iv049",type:"fill",q:"I learned from this experience that ___ intervention is more effective than ___ until a problem becomes serious.",a:"early ... waiting",exp:"Reflection is the bonus in STAR — what you learned. Showing you REFLECT on your practice signals a growth mindset. Australian Professional Standards for Teachers emphasise reflection."},
          {id:"iv050",type:"mc",q:"Which is the best 'Result' statement?",options:["I think it went well.","The student seemed happier after that.","The student's assessment grade improved from a C to an A, and they volunteered to present their project to the class — something they had never done before.","It worked out in the end."],a:2,exp:"Option 2 is specific, measurable (C to A), and shows personal growth (volunteered to present). Vague results ('went well', 'seemed happier', 'worked out') are unconvincing."},
          {id:"iv051",type:"error",q:"I have not had this situation before, so I cannot answer this question.",a:"While I have not encountered that exact scenario, a similar situation I can draw on is... During my practicum, I faced a challenge where [related example]. The approach I took was [action], and the result was [outcome]. I believe the same principles would apply here.",exp:"Never say 'I can't answer.' Instead, bridge to a related experience. Panels understand early-career teachers may not have every experience — they want to see your THINKING and adaptability."},
          {id:"iv052",type:"fill",q:"Looking back, if I could do it differently, I would have ___ the parents earlier and ___ additional support sooner.",a:"contacted ... sought",exp:"Showing self-awareness about what you would improve is POWERFUL. It demonstrates reflection, honesty, and growth. Panels trust candidates who can critically evaluate their own practice."},
          {id:"iv053",type:"mc",q:"'Tell me about a time you received negative feedback. How did you respond?' What is the panel looking for?",options:["That you never make mistakes.","That you can accept feedback gracefully, reflect on it, and use it to improve.","That you can defend yourself against criticism.","That you blame others for problems."],a:1,exp:"Growth mindset: accept feedback, reflect, improve. This is tied to Standard 6 of the Australian Professional Standards: 'Engage in Professional Learning.' Show you are coachable."},
          {id:"iv054",type:"open",q:"Using STAR, respond to: 'Tell me about a time you had to adapt your lesson on the spot.'",a:"During a Year 7 Technology lesson on the design process, I had planned a computer-based research activity (Situation). However, when students logged on, the school internet went down (Task: adapt quickly to maintain learning). I immediately switched to an analogue activity — I gave each group a physical product to analyse using the design criteria we had been studying, and they presented their findings to the class (Action). The lesson actually went better than planned because students were more hands-on and collaborative. My mentor teacher commented that my ability to think on my feet was a real strength (Result).",exp:"Excellent STAR for adaptability: unexpected tech failure, quick pivot to analogue activity, positive outcome, mentor feedback. This demonstrates resilience and resourcefulness."},
          {id:"iv055",type:"fill",q:"This experience taught me the importance of always having a ___ plan and being ready to ___ my teaching approach.",a:"backup ... adjust",exp:"Reflection/lesson learned: 'backup plan' and 'adjust approach' show professional preparedness. The ability to adapt is highly valued, especially in schools where technology can be unreliable."},
          {id:"iv056",type:"error",q:"In my country, teachers are very strict. I also like to be strict with students.",a:"I believe in having high expectations for all students while maintaining a supportive classroom culture. In my practicum, I established clear routines and expectations from day one, which created a calm and focused learning environment.",exp:"Reframe 'strict' as 'high expectations with support'. Reference Australian pedagogy. Show you understand the balance between structure and warmth that Australian schools value."},
          {id:"iv057",type:"fill",q:"I proactively ___ out to the student's parents and ___ a meeting to discuss strategies for support.",a:"reached ... arranged",exp:"'Reached out to' = contacted proactively. 'Arranged a meeting' = organised. These action verbs show initiative. STAR actions should always use strong, specific verbs."},
          {id:"iv058",type:"mc",q:"When the panel asks 'What is your greatest weakness?', what is the best approach?",options:["Say you have no weaknesses.","Name a genuine area for growth and explain what you are doing to improve it.","Make up a fake weakness like 'I work too hard.'","List several serious weaknesses honestly."],a:1,exp:"Name a REAL but manageable weakness, then show your improvement strategy. Example: 'Time management was a challenge early on — I now use a planning system that helps me prioritise effectively.' This shows self-awareness and growth."},
          {id:"iv059",type:"fill",q:"One area I am actively developing is my ___ in using data to inform my teaching. I have enrolled in a professional development course on ___ assessment practices.",a:"confidence ... formative",exp:"Honest weakness + concrete improvement action. 'Formative assessment' is key Australian education vocabulary. Showing you are ALREADY working on it demonstrates professionalism."},
          {id:"iv060",type:"error",q:"I do not like when students are lazy. I think students should try harder.",a:"When I notice a student is not engaging, I try to understand the underlying reason. Often, apparent disengagement stems from a lack of understanding or confidence. In those cases, I adjust my approach — perhaps breaking the task into smaller steps or offering a different entry point.",exp:"'Lazy' is a judgment, not a teaching response. Show diagnostic thinking: WHY is the student disengaged? What is your RESPONSE? This demonstrates professional judgement."},
          {id:"iv061",type:"open",q:"Using STAR, respond to: 'How have you built positive relationships with students from diverse backgrounds?'",a:"At my practicum school in western Sydney, I taught a Year 8 class with students from over 15 different cultural backgrounds (Situation). I wanted to create a classroom where every student felt they belonged (Task). I started each term with a 'cultural strengths' activity where students shared something from their background that they were proud of. I also learned basic greetings in several of my students' home languages and incorporated culturally diverse examples in my Technology projects (Action). Students became more willing to participate, and two students who had been very quiet told me it was the first time a teacher had asked about their culture. My mentor noted a visible improvement in class cohesion (Result).",exp:"Excellent STAR for cultural responsiveness. Specific strategies (cultural strengths activity, learning greetings), emotional impact (quiet students opening up), and professional validation (mentor feedback). This aligns with Australian Professional Standard 1.3."},
          {id:"iv062",type:"fill",q:"I believe that building ___ with students is the foundation of effective ___.",a:"rapport ... teaching",exp:"'Building rapport' = establishing a positive relationship. This is a core Australian teaching principle. Panels want teachers who prioritise relationships because engagement depends on trust."},
          {id:"iv063",type:"mc",q:"How long should a STAR response typically be?",options:["30 seconds — keep it brief.","2-3 minutes — detailed enough to show evidence but concise enough to hold attention.","10 minutes — give every possible detail.","As long as possible to fill time."],a:1,exp:"2-3 minutes is ideal. Too short lacks evidence; too long loses the panel's attention. Practise timing your responses. If the panel wants more detail, they will ask follow-up questions."},
          {id:"iv064",type:"fill",q:"After the ___, I reflected on what I had learned and ___ the strategy into my regular teaching practice.",a:"experience ... incorporated",exp:"'Incorporated into practice' = made it a regular part of teaching. This shows the experience led to lasting change, not just a one-off success. Reflection + integration = professional growth."},
          {id:"iv065",type:"error",q:"I am very patient with students. This is my best quality.",a:"One example of my patience in action: a Year 7 student struggled with a coding task for three lessons. Rather than giving the answer, I broke the problem into smaller steps and celebrated each milestone with her. By the fourth lesson, she solved it independently and her confidence soared.",exp:"'I am patient' is a claim. The corrected version SHOWS patience through a specific example. Show, don't tell. Panels want evidence, not self-assessment."}
        ]
      },      {
        id: "interview-teaching",
        title: "Teaching Philosophy & Pedagogy Questions",
        theory: "You will be asked about differentiation, classroom management, assessment practices, technology integration, and cultural responsiveness. Reference Australian frameworks: Quality Teaching Framework, Australian Professional Standards for Teachers, NESA syllabus outcomes. Show you know the Australian context.",
        exercises: [
          {id:"iv066",type:"mc",q:"What are the three dimensions of the NSW Quality Teaching Framework?",options:["Planning, Teaching, Assessing","Intellectual Quality, Quality Learning Environment, Significance","Curriculum, Pedagogy, Assessment","Engagement, Differentiation, Feedback"],a:1,exp:"The NSW Quality Teaching Framework has three dimensions: Intellectual Quality, Quality Learning Environment, and Significance. Referencing this in interviews shows you understand the NSW education context."},
          {id:"iv067",type:"fill",q:"I plan my lessons with clear ___ outcomes aligned to the NESA ___ for each stage.",a:"learning ... syllabus",exp:"'Learning outcomes' + 'NESA syllabus' = essential vocabulary. Every lesson should have outcomes drawn from the syllabus. Mentioning NESA by name shows you understand the NSW regulatory body."},
          {id:"iv068",type:"error",q:"I teach the same content to all students and hope they can understand.",a:"I differentiate my instruction by providing three tiers of activities: scaffolded tasks for students who need support, core tasks for the majority, and extension challenges for advanced learners.",exp:"'One size fits all' teaching is unacceptable in Australian schools. Differentiation is expected. The three-tier model (support, core, extension) is widely used and understood by panels."},
          {id:"iv069",type:"mc",q:"Which statement best describes differentiation?",options:["Giving weaker students easier work.","Adjusting content, process, product, or learning environment to meet the diverse needs of all learners.","Letting advanced students help struggling students.","Having different expectations for different students."],a:1,exp:"Differentiation is about adjusting content, process, product, or environment. It is NOT about lowering expectations. All students work toward the same outcomes but with different entry points and scaffolds."},
          {id:"iv070",type:"fill",q:"I use ___ assessment strategies such as exit tickets, peer feedback, and student self-reflection to monitor learning ___ the unit.",a:"formative ... throughout",exp:"'Formative assessment' = ongoing assessment FOR learning (not just OF learning). 'Throughout' shows it is not just a test at the end. Australian education heavily emphasises formative assessment."},
          {id:"iv071",type:"error",q:"Assessment is just a test at the end of the unit to give students a grade.",a:"Assessment is an ongoing process that includes both formative strategies to guide instruction and summative tasks to evaluate achievement against syllabus outcomes.",exp:"This shows understanding of assessment FOR learning (formative) and OF learning (summative). NESA requires both. Panels want teachers who assess throughout, not just at the end."},
          {id:"iv072",type:"mc",q:"What does 'explicit teaching' mean in Australian education?",options:["Being strict and controlling in the classroom.","Clearly explaining, modelling, and guiding students through new concepts before independent practice.","Teaching only what is in the textbook.","Telling students exactly what to write."],a:1,exp:"Explicit teaching = 'I do, We do, You do' — teacher models, guided practice, then independent practice. It is evidence-based and widely referenced in Australian education policy."},
          {id:"iv073",type:"fill",q:"I structure my lessons using the ___, ___, ___ model to gradually release responsibility to students.",a:"I do ... We do ... You do",exp:"Gradual Release of Responsibility: teacher demonstrates (I do), guided practice together (We do), independent practice (You do). This is the most commonly referenced lesson structure in Australian schools."},
          {id:"iv074",type:"open",q:"Write a response to: 'How do you differentiate your teaching for students with diverse learning needs?'",a:"Differentiation is central to my teaching practice. I plan every lesson with three tiers of activity: a scaffolded version for students who need additional support, which includes sentence starters, graphic organisers, and worked examples; a core task that meets the standard syllabus expectations; and an extension challenge that encourages higher-order thinking and real-world application. I also differentiate the process by offering students choice in how they demonstrate their learning — for example, a written report, a digital presentation, or a video explanation. I use formative assessment data to group students flexibly and adjust my instruction based on what the data tells me about their progress.",exp:"Comprehensive answer covering differentiation of content (three tiers), process (student choice), and assessment-informed grouping. References specific strategies (sentence starters, graphic organisers) that panels recognise."},
          {id:"iv075",type:"fill",q:"I use ___ grouping strategies based on formative assessment data, rather than permanently grouping students by ___.",a:"flexible ... ability",exp:"'Flexible grouping' = groups change based on current needs. 'Ability grouping' (permanent tracking) is discouraged in Australian education because it can limit student growth and reinforce inequality."},          {id:"iv076",type:"mc",q:"What is the difference between assessment FOR learning and assessment OF learning?",options:["There is no difference — they mean the same thing.","FOR learning is formative (ongoing, to guide instruction); OF learning is summative (final, to measure achievement).","FOR learning is easier; OF learning is harder.","FOR learning is for the teacher; OF learning is for the student."],a:1,exp:"Assessment FOR learning = formative (exit tickets, questioning, observations). Assessment OF learning = summative (exams, major tasks). Australian panels expect you to know this distinction clearly."},
          {id:"iv077",type:"fill",q:"I believe in creating a classroom culture where mistakes are seen as ___ opportunities, not as ___.",a:"learning ... failures",exp:"Growth mindset language: 'mistakes are learning opportunities'. This aligns with the Quality Learning Environment dimension of the QTF. Panels want to hear that your classroom is psychologically safe."},
          {id:"iv078",type:"error",q:"I use technology because students like playing on computers.",a:"I integrate technology purposefully to enhance learning outcomes — for example, using collaborative tools like Google Docs for peer editing, simulation software for design prototyping, and data visualisation tools to build analytical skills.",exp:"Technology must be PURPOSEFUL, not entertainment. Name specific tools and their learning purpose. 'Playing on computers' shows no pedagogical understanding of technology integration."},
          {id:"iv079",type:"mc",q:"Which Australian Professional Standard focuses on 'Know your students and how they learn'?",options:["Standard 1","Standard 3","Standard 5","Standard 7"],a:0,exp:"Standard 1: Know students and how they learn. This covers differentiation, cultural backgrounds, and learning needs. The seven standards are: 1) Know students, 2) Know content, 3) Plan, 4) Create environments, 5) Assess, 6) Professional learning, 7) Community engagement."},
          {id:"iv080",type:"fill",q:"I am familiar with the NESA ___ for Technology Mandatory and I plan my units to address the ___ outcomes for each stage.",a:"syllabus ... content",exp:"Naming the specific syllabus shows you have done your homework. 'Content outcomes' = what students must know and do. NESA syllabuses have both content and skills outcomes."},
          {id:"iv081",type:"error",q:"I am a good teacher because I have a lot of knowledge.",a:"My effectiveness as a teacher comes from my ability to make complex concepts accessible to all learners, build positive relationships, and use data to continuously improve my practice.",exp:"Knowledge alone doesn't make a good teacher. Panels want to see pedagogy (making content accessible), relationships, and data-driven practice. This aligns with multiple Australian Professional Standards."},
          {id:"iv082",type:"open",q:"Write a response to: 'How do you incorporate Aboriginal and Torres Strait Islander perspectives into your teaching?'",a:"I believe it is essential to embed Aboriginal and Torres Strait Islander perspectives authentically across the curriculum, not just as an add-on. In my Technology lessons, I have explored Indigenous engineering and design — for example, examining the sophisticated water management systems used by Aboriginal peoples for thousands of years. I also highlight the technological innovations of First Nations peoples, such as the boomerang as an aerodynamic tool and fish traps as sustainable food systems. I am committed to working with my school's community and local Elders to ensure these perspectives are represented respectfully and accurately.",exp:"This is a critical question in Australian education. Show you embed perspectives across curriculum (not just NAIDOC week), use specific examples, and mention community consultation. This aligns with NESA cross-curriculum priorities."},
          {id:"iv083",type:"fill",q:"Classroom management begins with clear ___ and consistent ___ that students understand from day one.",a:"expectations ... routines",exp:"'Expectations' and 'routines' are the foundation of Australian classroom management. Set them early, reinforce consistently, and be fair. Panels want to hear structure, not punishment."},
          {id:"iv084",type:"mc",q:"Which approach to classroom management is most valued in Australian schools?",options:["Punishment-focused: immediate consequences for misbehaviour.","Relationship-based: building trust, setting clear expectations, and using restorative practices.","Ignoring all bad behaviour and hoping it stops.","Strict discipline with no student input."],a:1,exp:"Relationship-based management with restorative practices is the current Australian best practice. Students are involved in setting expectations. Consequences exist but relationships come first."},
          {id:"iv085",type:"fill",q:"When a behavioural issue arises, I first try to ___ the situation by speaking to the student privately and using ___ practices to repair the relationship.",a:"de-escalate ... restorative",exp:"'De-escalate' = calm the situation. 'Restorative practices' = repairing harm through conversation, not just punishment. These are essential vocabulary for Australian school interviews."},
          {id:"iv086",type:"error",q:"If a student misbehaves, I give them detention immediately.",a:"When a student makes a poor choice, I first try to understand the reason behind the behaviour. I use a graduated response: a private conversation, a warning, a time-out, and only escalate to formal consequences if the behaviour persists. I also follow up with a restorative conversation.",exp:"Show a graduated response, not immediate punishment. Use 'poor choice' instead of 'misbehaves' (separates behaviour from identity). Restorative follow-up is essential."},
          {id:"iv087",type:"mc",q:"What does 'culturally responsive teaching' mean?",options:["Teaching about different countries in geography.","Recognising and valuing the cultural backgrounds of all students and using culturally relevant content and strategies.","Only teaching in English because it is Australia.","Celebrating cultural festivals once a year."],a:1,exp:"Culturally responsive teaching values diversity, uses culturally relevant content, and creates inclusive environments. It is not a one-day event but an ongoing approach embedded in daily practice."},
          {id:"iv088",type:"fill",q:"I use ___ strategies such as think-pair-share, exit tickets, and mini-whiteboards to check student understanding in ___ time.",a:"formative ... real",exp:"'Real-time' formative assessment strategies = checking understanding AS you teach. Think-pair-share, exit tickets, and mini-whiteboards are the three most commonly referenced strategies in Australian education."},
          {id:"iv089",type:"open",q:"Write a response to: 'How do you use technology to enhance student learning?'",a:"I use technology as a tool to enhance learning, not as a replacement for good teaching. In my Technology and IST classes, I integrate digital tools purposefully: Google Classroom for managing resources and providing timely feedback, collaborative platforms like Canva and Google Slides for student-created content, and coding environments like Scratch and Python for computational thinking. I also teach students to be critical consumers of digital information and responsible digital citizens. Importantly, I always have a non-digital backup plan in case technology fails — flexibility is key in any school environment.",exp:"Shows purposeful integration, names specific tools, includes digital citizenship, and has a backup plan. This demonstrates both technical competence and pedagogical wisdom."},
          {id:"iv090",type:"fill",q:"I am committed to ___ professional learning and I actively seek ___ to improve my teaching practice.",a:"ongoing ... feedback",exp:"'Ongoing professional learning' = continuous improvement. 'Actively seek feedback' = growth mindset. This aligns with Standard 6 of the Australian Professional Standards: engage in professional learning."},
          {id:"iv091",type:"mc",q:"What is Universal Design for Learning (UDL)?",options:["A building design framework for schools.","A framework for designing flexible learning experiences that provide multiple means of engagement, representation, and action/expression.","A technology platform for online learning.","A special education programme."],a:1,exp:"UDL provides multiple means of engagement (why), representation (what), and action/expression (how). It is about designing for ALL learners from the start, not adding modifications after. Increasingly referenced in Australian education."},
          {id:"iv092",type:"fill",q:"I believe that ___ feedback is one of the most powerful tools for improving student ___.",a:"timely ... outcomes",exp:"Research (Hattie, 2009) shows feedback has one of the highest effect sizes on student achievement. 'Timely' = given while the learning is fresh. Mentioning evidence-based practice impresses panels."},
          {id:"iv093",type:"error",q:"I think all students should get the same work because it is fair.",a:"I believe equity means giving each student what they need to succeed, which is different from giving every student the same thing. I plan with differentiated entry points so that all students can access the learning and demonstrate their understanding in ways that suit their strengths.",exp:"Equality (same for all) vs equity (each gets what they need). Australian education prioritises EQUITY. This distinction is important and panels often ask about it."},
          {id:"iv094",type:"fill",q:"I use ___ data from previous assessments to plan my units, ensuring that I address identified ___ in student knowledge.",a:"diagnostic ... gaps",exp:"'Diagnostic data' = pre-assessment information. 'Knowledge gaps' = areas where students need more support. Data-informed planning is a key expectation in Australian schools."},
          {id:"iv095",type:"mc",q:"Which of the following best describes 'student voice' in Australian education?",options:["Students talking in class.","Actively seeking and incorporating student feedback and perspectives into teaching and school decisions.","Students voting on what to learn.","Letting students teach the class."],a:1,exp:"'Student voice' = actively valuing student perspectives on their learning experience. This can include surveys, feedback forms, student leadership, and co-designing learning activities. It is increasingly prioritised."}
        ]
      },      {
        id: "interview-closing",
        title: "Asking Questions & Closing Strong",
        theory: "Always have 2-3 questions prepared for the panel. Good questions show research about the school and genuine interest. 'What does professional development look like here?', 'How does the school support new teachers?', 'What are the school priorities for the coming year?' Avoid questions about salary or leave in the first interview.",
        exercises: [
          {id:"iv096",type:"mc",q:"The panel asks 'Do you have any questions for us?' What is the best response?",options:["No, I think you covered everything.","Yes, I do. I noticed your school has a strong STEM focus. Could you tell me more about how the Technology faculty contributes to that vision?","How much does this job pay?","When can I start?"],a:1,exp:"Always have questions prepared. Asking about school programmes shows research and genuine interest. 'No questions' suggests lack of interest. Salary questions are inappropriate in the first interview."},
          {id:"iv097",type:"fill",q:"I would love to know more about the school's approach to ___ development for early-career ___.",a:"professional ... teachers",exp:"'Professional development for early-career teachers' shows you want to grow and you know the Australian terminology. ECT = early career teacher. Most schools have induction and mentoring programmes."},
          {id:"iv098",type:"error",q:"How many holidays do teachers get? And is there a car park?",a:"Could you tell me about the mentoring and induction programmes available for new staff? And how does the faculty collaborate on programming and assessment?",exp:"Holiday and parking questions are inappropriate for a first interview. Ask about professional growth, collaboration, and school culture instead. Logistics come after you get the offer."},
          {id:"iv099",type:"mc",q:"Which question shows you have researched the school?",options:["What subjects do you teach here?","I read in your annual report that literacy is a whole-school priority. How does the Technology faculty contribute to this?","Is this a good school?","Do you have many students?"],a:1,exp:"Referencing the annual report or school plan shows genuine research. Questions about subjects, reputation, or size suggest you have not done basic homework. Always check the school website beforehand."},
          {id:"iv100",type:"fill",q:"Could you describe the ___ culture within the faculty and how teachers typically ___ on programming?",a:"collaborative ... collaborate",exp:"'Collaborative culture' and 'collaborate on programming' (lesson/unit planning) are key phrases. This question tells the panel you VALUE teamwork, which is essential in Australian schools."},
          {id:"iv101",type:"open",q:"Write two thoughtful questions you could ask at the end of a teaching interview at a public high school.",a:"1. Your school plan mentions a focus on student wellbeing and engagement. Could you share some of the initiatives you have in place, and how I could contribute as a member of the Technology faculty? 2. What does the induction process look like for new staff, and is there a formal mentoring programme for early-career teachers?",exp:"Both questions show: research (school plan reference), genuine interest (how I can contribute), and professional awareness (induction, mentoring). These are questions panels remember positively."},
          {id:"iv102",type:"error",q:"Thank you. I hope you choose me. I really need this job.",a:"Thank you very much for your time today. I have really enjoyed learning more about the school and this role. I am confident that my skills and enthusiasm would be a strong fit, and I look forward to hearing from you.",exp:"Never express desperation ('I need this job'). Close with gratitude, confidence, and professionalism. Reiterate your interest and fit. Leave a positive final impression."},
          {id:"iv103",type:"fill",q:"Thank you for the opportunity to ___ with you today. I have thoroughly ___ our conversation.",a:"meet ... enjoyed",exp:"'Opportunity to meet' and 'enjoyed our conversation' = warm, professional closing. Use the past tense for the interview experience and present tense for your ongoing interest."},
          {id:"iv104",type:"mc",q:"What should you do immediately after leaving the interview room?",options:["Call a friend to complain about how it went.","Send a brief thank-you email to the contact person within 24 hours.","Post about it on social media.","Forget about it and move on."],a:1,exp:"A thank-you email within 24 hours is professional and memorable. Keep it brief: thank them for their time, reiterate your interest, mention one specific thing from the conversation. This is uncommon in Australia and will make you stand out."},
          {id:"iv105",type:"fill",q:"I am particularly interested in how the school supports students with ___ learning needs and how I can ___ to that effort.",a:"additional ... contribute",exp:"'Additional learning needs' = the Australian term for special educational needs. Asking about this shows you care about inclusivity. 'Contribute to that effort' = you want to be part of the solution."},          {id:"iv106",type:"error",q:"I don't have any questions. You explained everything very clearly.",a:"Yes, thank you. I was wondering — what are the school's key priorities for the next 12 months, and how does the Technology faculty fit into that vision?",exp:"Always ask at least one question. 'No questions' is a missed opportunity. Even if everything was clear, asking about future direction shows strategic thinking and genuine interest."},
          {id:"iv107",type:"mc",q:"Which closing statement is most professional?",options:["Thanks. Bye.","I really hope you pick me over the other candidates.","Thank you for your time. I am genuinely enthusiastic about this opportunity and I believe I could make a meaningful contribution to your school community.","So, did I get the job?"],a:2,exp:"Professional closing: gratitude + enthusiasm + value statement. Don't compare yourself to other candidates, ask about the decision on the spot, or be too casual. Leave them with a strong impression."},
          {id:"iv108",type:"fill",q:"I would welcome the opportunity to observe a lesson or visit the ___ before starting, if that would be ___.",a:"faculty ... possible",exp:"Offering to visit shows initiative and eagerness. 'If that would be possible' is polite and not presumptuous. Some schools do offer a tour or classroom visit before or after the interview."},
          {id:"iv109",type:"open",q:"Write a brief thank-you email to send within 24 hours of a teaching interview.",a:"Subject: Thank you — Technology Teacher Interview\n\nDear [Panel Chair's name],\n\nThank you for the opportunity to interview for the Technology Teacher position at [School Name] yesterday. I thoroughly enjoyed our conversation and learning more about the school's vision for STEM education.\n\nI was particularly excited to hear about the school's plans for the new design and technology workshop. I believe my experience with project-based learning and digital technologies would allow me to contribute meaningfully to this initiative.\n\nPlease do not hesitate to contact me if you require any further information. I look forward to hearing from you.\n\nKind regards,\n[Your name]",exp:"Brief, specific (references something discussed), reiterates interest, professional tone. This is uncommon in Australian teaching interviews and will distinguish you from other candidates."},
          {id:"iv110",type:"mc",q:"When is it appropriate to ask about salary in a teaching interview?",options:["During your self-introduction.","After you receive an offer, or when the panel raises it.","As your first question to the panel.","Never — teachers should not care about money."],a:1,exp:"Salary for NSW public school teachers is set by the award — it is not negotiable. If you have questions about classification or entitlements, ask AFTER receiving an offer or when the panel raises the topic."},
          {id:"iv111",type:"fill",q:"If offered this position, I would be ready to start ___ and I am happy to attend any ___ sessions before the term begins.",a:"immediately ... orientation",exp:"Showing readiness to start and willingness to attend orientation demonstrates enthusiasm and professionalism. 'Orientation' = induction sessions for new staff before term."},
          {id:"iv112",type:"error",q:"I will accept any position you offer me. I am not picky about what I teach.",a:"I am most confident teaching Technology and IST, though I am also willing to contribute to other faculty needs. I am flexible and enthusiastic about the opportunity to broaden my teaching experience.",exp:"Show primary expertise, then flexibility. Being 'not picky' sounds desperate and suggests you don't have clear strengths. Panels want confident specialists who are also adaptable."},
          {id:"iv113",type:"mc",q:"The panel says 'We will be in touch within two weeks.' What is the best response?",options:["Can you tell me sooner? I am very anxious.","That sounds great. I look forward to hearing from you. Thank you again for your time.","What if I don't hear from you? Should I call every day?","Two weeks is too long. I need to know now."],a:1,exp:"Accept the timeline graciously. If you haven't heard after the stated period, one polite follow-up email is appropriate. Pushing for a faster answer shows impatience, not enthusiasm."},
          {id:"iv114",type:"fill",q:"Is there anything else you would like me to ___ or any additional ___ I can provide to support my application?",a:"clarify ... information",exp:"This is an excellent final question — it gives the panel a chance to address any doubts. 'Clarify' and 'additional information' are professional terms. It shows confidence and thoroughness."},
          {id:"iv115",type:"open",q:"Write a confident closing statement for a teaching interview that summarises your key strengths.",a:"Thank you so much for your time today. I want to reiterate my genuine enthusiasm for this role. I bring a combination of strong content knowledge in Technology and IST, a commitment to differentiated instruction, and the ability to build positive relationships with students from diverse backgrounds. I am also passionate about professional growth and collaboration, and I am confident that I would be a valuable addition to your team. I look forward to the possibility of contributing to this school community.",exp:"Strong closing: gratitude, enthusiasm, three key strengths (content knowledge, differentiation, relationships), growth mindset, and team orientation. Practise this so it sounds natural, not rehearsed."},
          {id:"iv116",type:"error",q:"Thank you. Sorry for any mistakes in my English during the interview.",a:"Thank you for a wonderful conversation. I have really enjoyed learning about your school today and I am very excited about this opportunity.",exp:"NEVER apologise for your English. It draws attention to perceived weaknesses and undermines everything you just said. End on confidence and positivity. Your English got you this far — own it."},
          {id:"iv117",type:"fill",q:"I appreciate you taking the time to ___ with me today. Your school's commitment to ___ and ___ is truly inspiring.",a:"speak ... innovation ... inclusivity",exp:"Complimenting the school sincerely (not flattery) leaves a positive impression. Reference specific values from their website or school plan: 'innovation', 'inclusivity', 'student wellbeing', etc."},
          {id:"iv118",type:"mc",q:"What should you bring to a teaching interview?",options:["Nothing — just yourself.","A portfolio with sample lesson plans, work samples, qualifications, and references.","Your phone to show the panel your social media teaching page.","A gift for the panel members."],a:1,exp:"A teaching portfolio shows professionalism and preparation. Include: sample lessons, student work samples (de-identified), your qualifications, and reference contact details. Have both digital and print versions ready."},
          {id:"iv119",type:"fill",q:"I have brought a small ___ of my teaching work, including sample lesson plans and de-identified student ___ samples, which I am happy to share.",a:"portfolio ... work",exp:"Offering a portfolio shows preparation. 'De-identified' = student names removed (privacy requirement). Having physical evidence of your teaching is powerful and uncommon — it will impress panels."},
          {id:"iv120",type:"open",q:"Write a response to the panel's final words: 'Thank you for coming in. We really enjoyed meeting you. We will be in contact by the end of next week.'",a:"Thank you so much. I have really enjoyed meeting you all as well, and I am even more excited about this opportunity after our conversation today. I look forward to hearing from you. Have a wonderful rest of your day.",exp:"Warm, professional, brief. Mirror their friendliness ('enjoyed meeting you all as well'), express increased interest ('even more excited after our conversation'), and end with a pleasant farewell. Stand up, shake hands if offered, and leave with a smile."}
        ]
      }
    ]
  };

})();